import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; // THE BLUEPRINT for the current species

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    // 1. Create a "Adam/Eve" template for this shape
    this.template = ShapeFactory.create(shape, 'template');

    // 2. Spawn population based on this template
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism): void {
      // Used by Architect to inject a custom design
      this.template = JSON.parse(JSON.stringify(organism));
      this.spawnGenerationFromTemplate(true);
  }

  private spawnGenerationFromTemplate(isFreshStart: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (isFreshStart) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          // If fresh start, randomize genome slightly around the template's base (if it has one)
          // or just keep what the factory gave it. 
          // To ensure diversity in Gen 1, we mutate everyone slightly.
          this.mutateGenome(child.neuralGenome);

          this.population.push(child);
      }
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(this.simulationTime, false);

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  // NEW: Async Headless Simulation with Abort Signal
  public async computeGenerationAsync(
    targetDuration: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.15; // Reduced batch size for better responsiveness

      while (this.simulationTime < targetDuration) {
          // CRITICAL: Instant Kill Switch
          if (shouldStop()) {
             throw new Error("Evolution Aborted");
          }

          // Run a batch
          let batchTime = 0;
          while (batchTime < BATCH_DURATION && this.simulationTime < targetDuration) {
              this.simulationTime += dt;
              batchTime += dt;
              // True = FastMode (Reduced precision, No Self-Collision)
              this.updatePhysics(this.simulationTime, true);
          }

          // Report Progress
          if (onProgress) {
              onProgress(Math.min(1.0, this.simulationTime / targetDuration));
          }

          // Yield to Main Thread to allow UI events (like Stop Click) to process
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      // Calculate final fitness immediately
      this.population.forEach(org => {
         let cz = 0;
         org.nodes.forEach(n => { cz += n.pos.z; });
         org.fitness = cz / (org.nodes.length || 1);
      });
  }

  private updatePhysics(time: number, fastMode: boolean): void {
    this.population.forEach(org => {
      this.engine.updateOrganism(org, time, fastMode);

      // Update fitness continuously (helpful for visualization)
      let cz = 0;
      org.nodes.forEach(n => { cz += n.pos.z; });
      org.fitness = cz / (org.nodes.length || 1); 
    });
  }

  public evolve(): void {
    if (!this.template) return;

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    // Notify UI
    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism: Keep the champion exactly as is (but reset physical position)
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome); // Copy the WINNING brain
    nextGen.push(champion);

    // Fill the rest
    while (nextGen.length < this.populationSize) {
      // Pick a parent
      const parent = survivors[Math.floor(Math.random() * survivors.length)];

      // Create a fresh body
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);

      // Copy parent's brain
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);

      // Mutate brain
      this.mutateGenome(child.neuralGenome);

      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // Deep Clone Structure
      const clone: Organism = JSON.parse(JSON.stringify(template));
      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; // Clear runtime controller

      // Reset Physics State (Crucial!)
      // The template positions are the "Rest Pose" at (0,0,0).
      // We ensure oldPos = pos so velocity is 0.
      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                // Nudge weight
                arr[i] += (Math.random() - 0.5) * 0.5;
                // Clamp
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };

    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  // Ref for synchronous access inside tight loops
  const isAutoEvolvingRef = useRef(false);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [bestFitness, setBestFitness] = useState(0);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.TETRAHEDRON);
  const [isRunning, setIsRunning] = useState(false);
  const [isAutoEvolving, setIsAutoEvolvingState] = useState(false);

  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    service.onUpdate((pop) => {
        // We do NOT set state here every frame to avoid React render thrashing.
    });

    service.onGenComplete((best, gen) => {
        setBestFitness(best.fitness);
        setGeneration(gen);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => cancelAnimationFrame(requestRef.current!);
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);

    // Stop Auto
    isAutoEvolvingRef.current = false;
    setIsAutoEvolvingState(false);

    setIsProcessing(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    setBestFitness(0);
  }, []);

  const spawnCustom = useCallback((organism: Organism) => {
      setIsRunning(false);
      isAutoEvolvingRef.current = false;
      setIsAutoEvolvingState(false);
      setIsProcessing(false);

      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      setBestFitness(0);
      setCurrentShape(ShapeType.WORM); 
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // Async Logic for Auto Evolution
  const runAutoEvolution = useCallback(async () => {
      if (isProcessing) return; // Prevent double entry

      setIsProcessing(true);

      try {
          // 1. Compute Generation Async (Yielding to UI)
          // We pass a callback that checks our Ref. If ref is false, service throws error.
          await serviceRef.current.computeGenerationAsync(
              10.0, 
              () => !isAutoEvolvingRef.current, // Stop Signal
              (pct) => setProgress(pct)
          );

          // 2. Evolve (Only if we finished successfully)
          evolve();

          // 3. Reset for next round
          setProgress(0);
          setIsProcessing(false);

      } catch (e) {
          // If we aborted (or other error), we catch it here.
          console.log("Evolution Stopped or Aborted");
          setIsProcessing(false);
          // Do NOT evolve. We stay on the current generation.
      }
  }, [isProcessing, evolve]);

  const toggleAutoEvolve = useCallback(() => {
      const newState = !isAutoEvolvingRef.current;
      isAutoEvolvingRef.current = newState;
      setIsAutoEvolvingState(newState);

      // If turning ON, ensure regular run is off (optional, but cleaner)
      if (newState) setIsRunning(false);
  }, []);

  const loop = useCallback(() => {
    // If neither running nor auto, stop loop
    if (!isRunning && !isAutoEvolving) return;

    if (isAutoEvolving) {
        if (!isProcessing) {
            runAutoEvolution();
        }
        // While processing, we do nothing in this loop (we wait for async in runAutoEvolution)
    } else {
        // NORMAL MODE: 60 FPS Physics
        if (isRunning) {
            serviceRef.current.step(0.016);
        }
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isAutoEvolving, isProcessing, runAutoEvolution]);

  useEffect(() => {
    if (isRunning || isAutoEvolving) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, isAutoEvolving, loop]);

  return {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing, 
    progress,    
    currentShape,
    setIsRunning,
    toggleAutoEvolve, // Replaces setIsAutoEvolving
    reset,
    evolve,
    spawnCustom
  };
}

