// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Helper to convert pixel to axial (for clicking)
const pixelToHex = (x: number, z: number, size: number = 0.5) => {
    const q = (2./3 * x) / size;
    const r = (-1./3 * x + Math.sqrt(3)/3 * z) / size;
    return axialRound(q, r);
};

const axialRound = (q: number, r: number) => {
    let x = q;
    let z = r;
    let y = -x-z;

    let rx = Math.round(x);
    let rz = Math.round(z);
    let ry = Math.round(y);

    const x_diff = Math.abs(rx - x);
    const z_diff = Math.abs(rz - z);
    const y_diff = Math.abs(ry - y);

    if (x_diff > y_diff && x_diff > z_diff) {
        rx = -ry-rz;
    } else if (y_diff > z_diff) {
        ry = -rx-rz; // We don't use Y in axial, but needed for calc
    } else {
        rz = -rx-ry;
    }
    return { q: rx, r: rz };
};

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.2, 6), []);

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;

      for (const hit of intersects) {
          if (hit.object.name.startsWith('voxel') || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              break;
          }
      }

      if (hitPoint) {
          if (currentType === ShapeType.HEX_2D) {
              // Hex Logic
              // We project point to Y=0 plane (if hitting base) or use neighbor logic
              // For 2D Hex editor, we usually edit on a flat plane.
              // Let's assume we are editing on Y=0 or Y=currentLevel.
              // Simple: Snapping to Y=0 plane for now.

              const hex = pixelToHex(hitPoint.x, hitPoint.z, 0.6); // size match service
              setHoverCoord({ x: hex.q, y: 0, z: hex.r });

          } else {
              // Cube/Tetra Logic
              if (hitObject?.name.startsWith('voxel')) {
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;
                 const p = hitObject.position;
                 setHoverCoord({
                     x: Math.round(p.x + nx),
                     y: Math.round(p.y + ny),
                     z: Math.round(p.z + nz)
                 });
              } else {
                 // Hit floor
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
              }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // If Right click on existing voxel
      // We need to raycast specifically for existing objects to get the one to delete
      if (e.button === 2) {
         // deletion logic, pass coords of the HIT object
         raycaster.setFromCamera(pointer, camera);
         const intersects = raycaster.intersectObjects(scene.children, true);
         for(const hit of intersects) {
             if (hit.object.name.startsWith('voxel')) {
                 // Inverse map position to coord?
                 // Or store coord in userData?
                 const userData = hit.object.userData as GridCoord;
                 onCellClick(userData.x, userData.y, userData.z, true);
                 return;
             }
         }
      }

      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      {cells.map(c => {
          if (currentType === ShapeType.HEX_2D) {
              const {x, z} = hexToPixel(c.x, c.z, 0.6);
              return (
                  <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[x, 0.1, z]}
                    geometry={hexGeo}
                    material={materialHex}
                    name="voxel_hex"
                    userData={c}
                    rotation={[0, Math.PI/6, 0]} // Pointy top
                  />
              );
          } else {
              return (
                <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[c.x, c.y, c.z]} 
                    geometry={boxGeo} 
                    material={material}
                    name="voxel_cube"
                    userData={c}
                />
              );
          }
      })}

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX_2D ? (
                 <mesh 
                    position={[hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 0.1, hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} geometry={boxGeo} material={hoverMaterial} />
             )}
         </group>
      )}

      {/* Base Plane for Raycasting */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[40, 40]} />
      </mesh>

      {currentType === ShapeType.HEX_2D ? (
          // Hex Grid Helper (Custom line segments could go here, but simple plane is okay)
           <gridHelper args={[20, 20, 0x444444, 0x111111]} position={[0, -0.5, 0]} />
      ) : (
           <gridHelper args={[20, 20, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
      )}

    </group>
  );
};

