// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat
  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // Biases for neurons
  biases: number[];
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export interface Organism {
  id: string;
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Distance traveled
  generation: number;

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX_2D = 'HEX_2D', // 2D Hexagonal Layout
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number; 
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const numMuscles = muscles.length;
    const reservoirSize = 20;

    const genome: NeuralGenome = {
        synapseWeights: this.randomArray(numMuscles * 2),
        reservoirWeights: this.randomArray(reservoirSize * reservoirSize),
        outputWeights: this.randomArray(numMuscles * reservoirSize),
        biases: this.randomArray(nodes.length)
    };

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Furthest Forward Node)
    let maxZ = -Infinity;
    let headNode: Node | null = null;
    nodes.forEach(n => {
        if (n.pos.z > maxZ) {
            maxZ = n.pos.z;
            headNode = n;
        }
    });
    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    return {
      id,
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: []
    };
  }

  private static randomArray(size: number): number[] {
      return Array.from({ length: size }, () => (Math.random() * 1.0) - 0.5); 
  }

  private static createTetrahedron() {
    const f = 0.95; // High friction for grip
    const m = 4.0;  // Heavy mass

    const nodes: Node[] = [
      { id: 'n1', pos: { x: 0, y: 0, z: 1 }, oldPos: { x: 0, y: 0, z: 1 }, mass: m, friction: f },
      { id: 'n2', pos: { x: 1, y: 0, z: -0.7 }, oldPos: { x: 1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n3', pos: { x: -1, y: 0, z: -0.7 }, oldPos: { x: -1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n4', pos: { x: 0, y: 1.5, z: 0 }, oldPos: { x: 0, y: 1.5, z: 0 }, mass: m, friction: f },
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push({
            id: `n${x}${y}${z}`,
            pos: { x: px, y: py, z: pz },
            oldPos: { x: px, y: py, z: pz },
            mass: m, 
            friction: f
          });
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; // Belly slides a bit
    const footFriction = 0.98; // Feet grip hard
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            { id: `n${i}_a`, pos: { x: -0.5, y: 0, z: offset }, oldPos: { x: -0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_b`, pos: { x: 0.5, y: 0, z: offset }, oldPos: { x: 0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_top`, pos: { x: 0, y: 1, z: offset + 0.5 }, oldPos: { x: 0, y: 1, z: offset + 0.5 }, mass: m, friction: bellyFriction }
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, // Maximum stiffness for bones
          dnaIndex: 0,
          // Init Oscillator
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              // Init Oscillator
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
            });
          }
        }
      }
      return muscles;
    }
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { VectorOps } from './math';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; // Reduced terminal velocity

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.04; 
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.08; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // FRICTION THRESHOLD
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.5,
      timeStep: 0.016,
      shapeMemoryStrength: 0.35, // 35% natural tendency to return to rest shape
      ...config
    };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. NEURAL UPDATE (Only if Alive)
    if (organism.isAlive) {
        if (!organism.brain) {
            organism.brain = new BrainController(organism);
        }
        if (organism.brain instanceof BrainController) {
            organism.brain.update(this.config.timeStep);
        }
    } else {
        // RAGDOLL MODE: If dead, muscles lose all stiffness/power
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
    }

    // 2. PHYSICS INTEGRATION
    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      node.oldPos = VectorOps.copy(node.pos);

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.3;

    for (const muscle of organism.muscles) {
        const n1 = organism.nodes.find(n => n.id === muscle.nodeA);
        const n2 = organism.nodes.find(n => n.id === muscle.nodeB);

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT (The Actuator)
        let activeTarget = muscle.targetLength || muscle.baseLength;
        // Safety limit to prevent implosion
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        // Stiffness varies based on state (Bone vs Soft)
        let stiffness = muscle.stiffness;
        if (dist < activeTarget) stiffness = 1.0; 
        else if (dist > activeTarget * 1.5) stiffness = 0.8; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT (The Pillar)
        // This force always pulls towards the original Blueprint (baseLength).
        // It provides structural integrity regardless of neural output.
        // NOTE: If dead (stiffness low), memory strength should also reduce to simulate "limpness"
        const currentMemoryStrength = organism.isAlive ? MEMORY_STRENGTH : MEMORY_STRENGTH * 0.1;
        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;

        // Sum the corrections. 
        let totalCorrection = activeCorrection + memoryCorrection;

        // Apply Relaxation Factor (Iterative Solver Stability)
        totalCorrection *= this.RELAXATION_FACTOR;

        // --- DAMPING ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVelSq = rvx*rvx + rvy*rvy + rvz*rvz;
        const relVel = Math.sqrt(relVelSq);

        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);

        const vRelProj = rvx * nx + rvy * ny + rvz * nz;
        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;

      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  // Soft repulsion (Relaxed)
                  const fx = (dx / dist) * overlap * 0.2; // Gentle push
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { 
                      n1.pos.x += fx; 
                      n1.pos.y += fy; 
                      n1.pos.z += fz; 
                  }
                  if (!n2.isFixed) { 
                      n2.pos.x -= fx; 
                      n2.pos.y -= fy; 
                      n2.pos.z -= fz; 
                  }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {

        node.pos.y = RADIUS;

        const vx = node.pos.x - node.oldPos.x;
        const vz = node.pos.z - node.oldPos.z;
        const velocitySq = vx*vx + vz*vz;

        // If dead, friction increases (they slump)
        const deadFrictionBonus = organism.isAlive ? 0 : 0.3;
        const gripFactor = Math.max(0, 1.0 - (node.friction || 0.5) - deadFrictionBonus);

        if (velocitySq < 0.0005) {
             node.oldPos.x = node.pos.x;
             node.oldPos.z = node.pos.z;
        } else {
             node.oldPos.x = node.pos.x - vx * gripFactor;
             node.oldPos.z = node.pos.z - vz * gripFactor;
        }
      } 
    }
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; // Energy lost per second
  private readonly HUNGER_ACCEL = 1.15; // 15% faster depletion per second of hunger
  private readonly FOOD_ENERGY = 30;
  private readonly FOOD_RADIUS = 0.5;

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism): void {
      this.template = JSON.parse(JSON.stringify(organism));
      this.spawnGenerationFromTemplate(true);
  }

  private spawnGenerationFromTemplate(isFreshStart: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (isFreshStart) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);
          this.mutateGenome(child.neuralGenome);

          // Spawn Food Track for this creature
          child.visibleFood = this.generateFoodTrack();

          this.population.push(child);
      }
  }

  private generateFoodTrack(): FoodItem[] {
      const food: FoodItem[] = [];
      // Create a corridor of food along +Z (Forward)
      // Spacing gets wider further out to encourage speed
      for(let i=1; i<=20; i++) {
          const z = i * 3.5; // Every 3.5 meters
          const x = (Math.random() - 0.5) * 2.0; // Mild zigzag
          food.push({
              id: `f_${i}`,
              pos: { x, y: 0.2, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, // Just a safety cap (e.g. 120s)
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.15; 

      // RUN UNTIL EXTINCTION (or Safety Time)
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt;

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); // Hunger & Eating Logic

              // Check Extinction
              allDead = !this.population.some(org => org.isAlive);
          }

          // Progress is now Ratio of (Time / SafetyCap) OR (DeadCount / Total)
          // Let's use DeadCount for better feedback
          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);

          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      // Physics Engine handles dead/alive physics state (ragdoll vs active)
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          if (!org.isAlive) return;

          // 1. HUNGER CALCULATIONS
          org.hungerTime += dt;

          // Exponential Multiplier: Starts at 1.0, grows by 15% every second since last meal
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);

          // Energy Decay
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          // Death Check
          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              // Fitness is locked at death moment
              this.calculateFitness(org); 
          }

          // 2. EATING LOGIC
          // Find Head
          const head = org.nodes.find(n => n.isHead);
          if (!head) return; // Should not happen

          // Check collisions with visible food
          // optimization: Only check first 2 unconsumed items (since they are ordered by Z)
          let checkCount = 0;
          for (const food of org.visibleFood) {
              if (food.consumed) continue;
              if (checkCount++ > 2) break; // Optimization

              const dist = VectorOps.distance(head.pos, food.pos);
              if (dist < this.FOOD_RADIUS) {
                  // YUM!
                  food.consumed = true;
                  org.energy += food.energyValue;
                  if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;

                  // RESET HUNGER MULTIPLIER
                  org.hungerTime = 0;
                  org.foodEaten++;
              }
          }
      });
  }

  private calculateFitness(org: Organism) {
      // Fitness = Distance + (Food * Bonus)
      // Distance is primary, food enables distance.
      let cz = 0;
      org.nodes.forEach(n => { cz += n.pos.z; });
      const avgZ = cz / org.nodes.length;

      // If they died early, penalized. If they ate, rewarded heavily.
      org.fitness = Math.max(0, avgZ) + (org.foodEaten * 5.0);
  }

  private finalizeFitness() {
      this.population.forEach(org => this.calculateFitness(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); // Ensure final scores

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack();
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);
      this.mutateGenome(child.neuralGenome);

      // New Food Track
      child.visibleFood = this.generateFoodTrack();

      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      const clone: Organism = JSON.parse(JSON.stringify(template));
      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      // Reset Physics
      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      // Reset Metabolism
      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; // Will be populated by spawner

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                arr[i] += (Math.random() - 0.5) * 0.5;
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };
    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
}

import React, { useMemo } from 'react';
