import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Organism } from '../../domain/types';

interface CreatureViewProps {
  organism: Organism;
  isGhost?: boolean;
}

export const CreatureView: React.FC<CreatureViewProps> = ({ organism, isGhost = false }) => {
  const groupRef = useRef<THREE.Group>(null);
  const nodeRefs = useRef<THREE.Mesh[]>([]);
  const muscleRefs = useRef<THREE.Mesh[]>([]);

  const nodeGeo = useMemo(() => new THREE.SphereGeometry(0.08, 12, 12), []);
  const muscleGeo = useMemo(() => new THREE.CylinderGeometry(0.03, 0.03, 1, 6), []);

  const colorRed = useMemo(() => new THREE.Color(0xff3333), []);
  const colorBlue = useMemo(() => new THREE.Color(0x3333ff), []);
  const colorWhite = useMemo(() => new THREE.Color(0xffffff), []);
  const colorYellow = useMemo(() => new THREE.Color(0xffff00), []); // Neuron Active
  const colorGhost = useMemo(() => new THREE.Color(0x444444), []);

  // NEW: Head Color and Dead Color
  const colorHead = useMemo(() => new THREE.Color(0x1a1a1a), []); // Dark Charcoal
  const colorDead = useMemo(() => new THREE.Color(0x52525b), []); // Zinc 600

  useFrame(() => {
    if (!groupRef.current) return;

    // 1. Sync Nodes (Joints)
    organism.nodes.forEach((node, i) => {
      const mesh = nodeRefs.current[i];
      if (mesh) {
        mesh.position.set(node.pos.x, node.pos.y, node.pos.z);

        const mat = mesh.material as THREE.MeshStandardMaterial;

        if (!organism.isAlive) {
            // Corpse
            mat.color.copy(colorDead);
            mat.opacity = 1;
            mat.transparent = false;
        } else if (isGhost) {
            mat.color.copy(colorGhost);
            mat.opacity = 0.2;
            mat.transparent = true;
        } else if (node.isHead) {
            // Head Node
            mat.color.copy(colorHead);
            mat.opacity = 1;
        } else {
            // Normal Node with Activation
            const activation = node.activation || 0;
            const baseColor = colorWhite.clone().lerp(colorYellow, activation);
            mat.color.copy(baseColor);
            mat.opacity = 1;
        }
      }
    });

    // 2. Sync Muscles (Struts)
    organism.muscles.forEach((muscle, i) => {
      const mesh = muscleRefs.current[i];
      if (mesh) {
        const nA = organism.nodes.find(n => n.id === muscle.nodeA);
        const nB = organism.nodes.find(n => n.id === muscle.nodeB);

        if (nA && nB) {
          const start = new THREE.Vector3(nA.pos.x, nA.pos.y, nA.pos.z);
          const end = new THREE.Vector3(nB.pos.x, nB.pos.y, nB.pos.z);
          const mid = start.clone().add(end).multiplyScalar(0.5);
          mesh.position.copy(mid);
          mesh.lookAt(end);
          mesh.rotateX(Math.PI / 2); 
          const currentLen = start.distanceTo(end);
          mesh.scale.set(1, currentLen, 1);

          const mat = mesh.material as THREE.MeshStandardMaterial;

          if (!organism.isAlive) {
             mat.color.copy(colorDead);
             mat.opacity = 1;
          } else if (isGhost) {
            mat.color.copy(colorGhost);
            mat.opacity = 0.1;
            mat.transparent = true;
          } else {
            const target = muscle.targetLength || muscle.baseLength;
            const base = muscle.baseLength;
            const ratio = target / base;

            if (ratio < 0.98) {
              mat.color.lerpColors(colorWhite, colorRed, Math.min(1, (1 - ratio) * 5));
            } else if (ratio > 1.02) {
              mat.color.lerpColors(colorWhite, colorBlue, Math.min(1, (ratio - 1) * 5));
            } else {
              mat.color.copy(colorWhite);
            }
            mat.opacity = 1.0;
            mat.transparent = false;
          }
        }
      }
    });
  });

  return (
    <group ref={groupRef}>
      {organism.nodes.map((node, i) => (
        <mesh
          key={node.id}
          ref={(el) => { if(el) nodeRefs.current[i] = el; }}
          geometry={nodeGeo}
        >
          <meshStandardMaterial color={isGhost ? "#666" : "white"} />
        </mesh>
      ))}

      {organism.muscles.map((muscle, i) => (
        <mesh
          key={muscle.id}
          ref={(el) => { if(el) muscleRefs.current[i] = el; }}
          geometry={muscleGeo}
        >
           <meshStandardMaterial color="white" />
        </mesh>
      ))}
    </group>
  );
};

import React from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { Organism } from '../../domain/types';
import { CreatureView } from './CreatureView';
import { FoodView } from './FoodView';

interface LabSceneProps {
  population: Organism[];
  showBestOnly: boolean;
}

export const LabScene: React.FC<LabSceneProps> = ({ population, showBestOnly }) => {
  // If Show Best Only: We render ONLY index 0
  // If Show All: We render ALL

  const organismsToRender = showBestOnly 
    ? [population[0]].filter(Boolean) 
    : population;

  // We only show food for the "Primary" organism to avoid visual clutter
  // Primary is Index 0 (Best/Leader)
  const primaryOrganism = population[0];

  return (
    <div className="w-full h-full bg-slate-900">
      <Canvas shadows dpr={[1, 2]}>
        <PerspectiveCamera makeDefault position={[6, 4, 8]} fov={45} />
        <OrbitControls makeDefault target={[0, 0.5, 0]} maxPolarAngle={Math.PI / 2 - 0.1} />

        <ambientLight intensity={0.5} />
        <directionalLight 
          position={[10, 20, 5]} 
          intensity={1.2} 
          castShadow 
          shadow-mapSize={[2048, 2048]} 
        />

        <group>
            {organismsToRender.map((org, index) => {
                const isGhost = showBestOnly ? false : (org !== population[0]);

                return (
                  <CreatureView 
                    key={org.id} 
                    organism={org} 
                    isGhost={isGhost} 
                  />
                );
            })}
        </group>

        {/* Render Food (Only for the leader to keep scene clean) */}
        {primaryOrganism && (
            <FoodView foodItems={primaryOrganism.visibleFood} />
        )}

        {/* Floor Grid */}
        <Grid 
            position={[0, -0.01, 0]} 
            args={[40, 40]} 
            cellColor="#334155" 
            sectionColor="#64748b" 
            fadeDistance={30}
            infiniteGrid
        />
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.05, 0]} receiveShadow>
          <planeGeometry args={[100, 100]} />
          <meshStandardMaterial color="#0f172a" roughness={0.8} metalness={0.2} />
        </mesh>

      </Canvas>
    </div>
  );
};

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
    this.clear();
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    // For Hex, we use x=q, z=r, y is ignored (0)
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateComplexLifeform() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    // Architecture Parameters
    const bodyLength = range(4, 7);
    const bodyHeight = range(2, 3); 
    const zOffset = -Math.floor(bodyLength / 2);

    // 1. Spine Core (The backbone)
    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        // Central Bone
        this.setCell(0, bodyHeight, absZ, true);

        // Ribcage/Bulk (50% chance to add block above or below for volume)
        if (rng() > 0.5) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.5 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    // 2. Limbs (Procedural "Growth")
    // We generate on Right side (+X), then mirror later.
    const numLegPairs = range(2, 3); // 2 or 3 pairs usually
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        // Distribute legs along spine
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;

        // Path to ground
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        // Shoulder (Force outward)
        cx++;
        this.setCell(cx, cy, cz, true);

        // Grow down to floor
        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            // Decision: Go Down, or Go Out?
            const moveDown = rng() > 0.3; // Bias towards gravity

            if (moveDown) {
                cy--;
            } else {
                // Grow outward or shift Z (Stance)
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }

            this.setCell(cx, cy, cz, true);
        }

        // Foot Pad (Stability) at Y=0
        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true); // Outer toe
            this.setCell(cx - 1, 0, cz, true); // Inner toe
            this.setCell(cx, 0, cz + 1, true); // Front toe
            this.setCell(cx, 0, cz - 1, true); // Back toe
        }
    }

    // 3. Head / Tail Features
    // Head (Front +Z)
    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);

    // Tail (Back -Z)
    if (rng() > 0.6) {
        let tailZ = zOffset - 1;
        let tailY = bodyHeight;
        for(let t=0; t<range(1, 3); t++) {
            this.setCell(0, tailY, tailZ, true);
            tailZ--;
            // Tail tends to drift up or down
            if(rng() > 0.5) tailY++; 
        }
    }

    // 4. Apply Symmetry
    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      // Random Walk
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;

          // Bounds check roughly
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX_2D) {
              // No mirroring for HEX MVP
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  // --- EXPORT TO PHYSICS ---

  public generateOrganism(id: string): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // 1. Create Nodes
      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c, i) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          if (this.type === ShapeType.HEX_2D) {
              // Hex Axial to Cartesian (Flat Top Hexagons)
              // x = size * 3/2 * q
              // z = size * sqrt(3) * (r + q/2)
              // We map Blueprint X -> q, Blueprint Z -> r. Blueprint Y is usually 0.
              const size = scale * 0.6; // Slightly smaller hexes
              const q = c.x;
              const r = c.z;

              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);
              py = 0.5; // Start slightly above ground (2D creature lies flat)

              // If user used Y layers in Hex (stacking hexagons?), we can add to py
              py += c.y * scale; 

          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              // Offset Lattice logic
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = c.y * (scale * 0.82) + 0.5;
          } else {
              // CUBE
              px = c.x * scale;
              py = c.y * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction
          });
      });

      // 2. Create Muscles (Connections)
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: 1.0, // Increased stiffness to match engine
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX_2D) {
              // Hex Neighbors (Axial coords)
              // (q+1, r), (q+1, r-1), (q, r-1), (q-1, r), (q-1, r+1), (q, r+1)
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // CROSS-BRACING for HEX (Prevent Shearing)
              // Connect (q,r) to (q+1, r+1) etc. (Long Diagonals)
              // Hex has 3 major axes. We already connected neighbors.
              // To make rigid triangles inside the hex, we need center point?
              // No, triangular lattice is rigid.
              // But let's add long-range connections to "stiffen" the plate.
              const diagonals = [
                 {dq: 2, dr: -1}, {dq: 1, dr: -2}, {dq: -1, dr: -1},
                 {dq: -2, dr: 1}, {dq: -1, dr: 2}, {dq: 1, dr: 1}
              ];
              diagonals.forEach(off => {
                 const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0); // Stiff bracing
              });

              // Also check layer up/down if 3D Hex
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [
                  {dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0},
                  {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0},
                  {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1},
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              // Cross-Bracing
              const diagonals = [
                  {dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0},
                  {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1},
                  {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}
              ];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 3. Genome
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      return {
          id,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: 0,
          generation: 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

