                        style={{ width: `${progress * 100}%` }}
                      />
                  </div>
               </div>
            ) : (
                <div className="text-[10px] text-slate-500 leading-tight text-center">
                  Enable 'AUTO EVOLVE' to fast-forward evolution. The simulation runs in background batches.
                </div>
            )}
        </div>

      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { LabScene } from './src/infrastructure/visuals/LabScene';
import { Dashboard } from './src/ui/Dashboard';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintViewUpdated } from './src/infrastructure/visuals/BlueprintView';
import { ArchitectControls } from './src/ui/ArchitectControls';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType } from './src/domain/types';

function App() {
  const {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing,
    progress,
    currentShape,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  const [mode, setMode] = useState<'LAB' | 'ARCHITECT'>('LAB');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // Architect State
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [archType, setArchType] = useState(ShapeType.CUBE);

  const handleArchCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      if (isRight) {
          blueprintService.setCell(x, y, z, false);
      } else {
          blueprintService.setCell(x, y, z, true);
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchGenerate = (type: string) => {
      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'procedural') blueprintService.generateLargeBeast(); // Legacy Fallback

      if (type === 'floor') blueprintService.applyFloorFill();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchType = (t: ShapeType) => {
      setArchType(t);
      blueprintService.setType(t);
      setBlueprintCells(blueprintService.getCells());
  };

  const handleSpawn = () => {
      const organism = blueprintService.generateOrganism('custom_proto');
      spawnCustom(organism);
      setMode('LAB');
  };

  return (
    <div className="relative w-full h-full bg-slate-900">

      {/* MODE TOGGLE */}
      <div className="absolute top-4 right-1/2 translate-x-1/2 z-10 flex bg-slate-800 rounded-full p-1 border border-slate-700">
          <button 
            onClick={() => setMode('LAB')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'LAB' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              LAB
          </button>
          <button 
            onClick={() => setMode('ARCHITECT')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'ARCHITECT' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              ARCHITECT
          </button>
      </div>

      {mode === 'LAB' ? (
          <>
            <LabScene 
                population={population} 
                showBestOnly={showBestOnly}
            />
            <Dashboard 
                generation={generation}
                bestFitness={bestFitness}
                isRunning={isRunning}
                isAutoEvolving={isAutoEvolving}
                isProcessing={isProcessing}
                progress={progress}
                currentShape={currentShape}
                onReset={reset}
                onToggleRun={() => setIsRunning(!isRunning)}
                onToggleAutoEvolve={toggleAutoEvolve} 
                showBestOnly={showBestOnly}
                setShowBestOnly={setShowBestOnly}
                onSave={saveCreature}
                onLoad={loadCreature}
            />
            {/* Instruction Toast */}
            {!isRunning && generation === 1 && !isAutoEvolving && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-black/50 text-white px-4 py-2 rounded-full backdrop-blur text-sm pointer-events-none animate-pulse">
                    Press RESUME to start the simulation
                </div>
            )}
          </>
      ) : (
          <>
            {/* ARCHITECT 3D VIEW */}
            <div className="w-full h-full cursor-crosshair">
                <Canvas shadows dpr={[1, 2]}>
                    <PerspectiveCamera makeDefault position={[8, 8, 8]} fov={45} />
                    <OrbitControls makeDefault target={[0, 0, 0]} />
                    <BlueprintViewUpdated
                        cells={blueprintCells} 
                        onCellClick={handleArchCellClick}
                        currentType={archType}
                    />
                </Canvas>
            </div>

            <ArchitectControls 
                onClear={() => { blueprintService.clear(); setBlueprintCells([]); }}
                onSetType={handleArchType}
                onGenerate={handleArchGenerate}
                onSpawn={handleSpawn}
                currentType={archType}
                cellCount={blueprintCells.length}
            />
          </>
      )}

    </div>
  );
}

export default App;

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat
  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // Biases for neurons
  biases: number[];
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export interface Organism {
  id: string;
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Distance traveled
  generation: number;

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number; 
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
    // We no longer clear() here. 
    // This allows the user to view the same voxel data interpreted through different lattices.
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();

      // Strategy: The "Stable Walker"
      // 10-15 voxels. 
      // Strong focus on Ground Contact and Central Mass.

      const length = 4 + Math.floor(rng() * 3); // 4 to 6 long
      const wideStance = rng() > 0.4; // 60% chance of wide legs
      const legX = wideStance ? 2 : 1;

      // 1. Central Spine (Chassis)
      // Raised off ground (y=1) to allow leg movement
      for(let z=0; z<length; z++) {
          this.setCell(0, 1, z, true);
      }

      // 2. Head (Front + Center + High)
      // Always at the very front (max Z)
      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);

      // NEW: 50% chance to grow a Neck (Y=3) to reach high food
      if (rng() > 0.5) {
          this.setCell(0, 3, headZ, true);
      }

      // 3. Legs (Stabilizers)
      // We place legs at the rear and near the front (but behind head)
      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          // Foot on ground
          this.setCell(legX, 0, z, true);
          // Knee/Hip connector to spine
          this.setCell(1, 1, z, true);

          // If very wide, need an intermediate strut for stability
          if (legX === 2) {
              this.setCell(1, 0, z, true); // Block under the hip
          }
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      // 4. Body Mass / Ribs
      // Add a few random blocks to the side of the spine for structural integrity
      // Avoid "useless appendages" by keeping them attached to spine
      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) {
               this.setCell(1, 1, z, true);
           }
      }

      // 5. Apply Symmetry
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    // Architecture Parameters
    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    // 1. Spine Core (The backbone)
    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        // Central Bone
        this.setCell(0, bodyHeight, absZ, true);

        // Ribcage/Bulk (60% chance to add block above or below for volume)
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    // 2. Limbs (Procedural "Growth")
    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;

        // Path to ground
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        // Shoulder
        cx++;
        this.setCell(cx, cy, cz, true);

        // Grow down to floor
        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        // Foot Pad
        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    // 3. Head (Front +Z)
    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    // Neck extension
    this.setCell(0, bodyHeight - 1, headZ, true);

    // 4. Apply Symmetry
    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      // Random Walk
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;

          // Bounds check roughly
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              // Simple X mirroring for Axial coordinates is tricky, 
              // but purely flipping 'x' (q) often works for visual symmetry 
              // depending on orientation.
              const mx = -x;
              newCells.set(`${mx},${y},${z}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  // --- EXPORT TO PHYSICS ---

  public generateOrganism(id: string): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // 1. Create Nodes
      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c, i) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          if (this.type === ShapeType.HEX) {
              // 3D Hex Prism logic
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;

              // Standard Flat-topped or Pointy-topped conversion
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);

              // Vertical Stacking
              const hexHeight = scale * 0.7; // Slightly shorter than wide for stability
              py = 0.5 + c.y * hexHeight; 

          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = c.y * (scale * 0.82) + 0.5;
          } else {
              // CUBE
              px = c.x * scale;
              py = c.y * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);

      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });

      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);

      let headNode: Node | null = null;
      let minAbsX = Infinity;

      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // 3. Create Muscles (Connections)
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              // --- HORIZONTAL NEIGHBORS (6 directions) ---
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- VERTICAL NEIGHBORS (Up/Down) ---
              // This turns the flat sheet into a 3D Honeycomb Prism structure
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- CROSS BRACING (Optional but good for rigidity) ---
              // Connect (x,y,z) to neighbors at (y+1) or (y-1) for diagonal strength
              // Only simple diagonals for now to avoid clutter
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [
                  {dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0},
                  {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0},
                  {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1},
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [
                  {dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0},
                  {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1},
                  {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}
              ];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      return {
          id,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: 0,
          generation: 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

import React, { useState, useMemo } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []); // Taller prism

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;

      for (const hit of intersects) {
          if (hit.object.name.startsWith('voxel') || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              break;
          }
      }

      if (hitPoint) {
          if (currentType === ShapeType.HEX) {
              // --- HEX LOGIC ---
              if (hitObject?.name === 'voxel_hex') {
                  const data = hitObject.userData as GridCoord;

                  // Transform world normal to local rotation of the hex mesh?
                  // Our hex meshes are rotated 30 deg (PI/6) on Y usually, or not.
                  // Simpler: Check Up/Down first.

                  // Convert normal to world space if needed (usually face normal is local to geometry, but raycaster returns world? No, raycaster face.normal is local?)
                  // THREE.Raycaster returns face normal in object space (usually). 
                  // But we need to be careful. Let's rely on hitPoint relative to object center.

                  const relX = hitPoint.x - hitObject.position.x;
                  const relY = hitPoint.y - hitObject.position.y;
                  const relZ = hitPoint.z - hitObject.position.z;

                  // 1. Vertical Stacking (Top/Bottom Faces)
                  // The Cylinder is 0.5 high. So Top is ~0.25, Bottom ~ -0.25
                  if (relY > 0.23) {
                      setHoverCoord({ x: data.x, y: data.y + 1, z: data.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: data.x, y: data.y - 1, z: data.z });
                       return;
                  }

                  // 2. Horizontal Neighbors (Side Faces)
                  // We need to map the hit vector angle to the 6 neighbor directions.
                  // Angle in X/Z plane.
                  const angle = Math.atan2(relZ, relX); // -PI to PI
                  // Convert to degrees for easier debugging mental model: -180 to 180
                  // Hex flat sides are at 0, 60, 120... or 30, 90, 150 depending on rotation.
                  // Our mesh has rotation [0, Math.PI/6, 0].

                  // Simple brute force: Find which neighbor center is closest to hitPoint (projected to plane)
                  const size = 0.6;
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(data.x + n.q, data.z + n.r, size);
                       // We compare world positions
                       const wx = pos.x; 
                       const wz = pos.z; 

                       const dx = wx - hitPoint!.x;
                       const dz = wz - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: data.x + bestNeigh.q, y: data.y, z: data.z + bestNeigh.r });
                  }

              } else {
                  // Hit Floor (Y=0 plane)
                  // Map X/Z to Hex Grid
                  // We need to invert the hexToPixel math.
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  // Round to nearest Hex
                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else if (y_diff > z_diff) {
                      // ry = -rx-rz; 
                  } else {
                      rz = -rx-ry;
                  }

                  setHoverCoord({ x: rx, y: 0, z: rz });
              }

          } else {
              // --- CUBE/TETRA LOGIC ---
              if (hitObject?.name.startsWith('voxel')) {
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;
                 const p = hitObject.position;
                 setHoverCoord({
                     x: Math.round(p.x + nx),
                     y: Math.round(p.y + ny),
                     z: Math.round(p.z + nz)
                 });
              } else {
                 // Hit floor
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
              }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // If Right click on existing voxel
      // We need to raycast specifically for existing objects to get the one to delete
      if (e.button === 2) {
         raycaster.setFromCamera(pointer, camera);
         const intersects = raycaster.intersectObjects(scene.children, true);
         for(const hit of intersects) {
             if (hit.object.name.startsWith('voxel')) {
                 const userData = hit.object.userData as GridCoord;
                 onCellClick(userData.x, userData.y, userData.z, true);
                 return;
             }
         }
      }

      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      {cells.map(c => {
          if (currentType === ShapeType.HEX) {
              const {x, z} = hexToPixel(c.x, c.z, 0.6);
              // Vertical Spacing for Cylinders (Height 0.5)
              // Gap is small or zero. Let's say 0.5 height, positioned at y * 0.5 + 0.25
              const hexHeight = 0.5;
              const yPos = c.y * hexHeight + (hexHeight/2);

              return (
                  <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[x, yPos, z]}
                    geometry={hexGeo}
                    material={materialHex}
                    name="voxel_hex"
                    userData={c}
                    rotation={[0, Math.PI/6, 0]} // Pointy top orientation
                  />
              );
          } else {
              return (
                <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[c.x, c.y, c.z]} 
                    geometry={boxGeo} 
                    material={material}
                    name="voxel_cube"
                    userData={c}
                />
              );
          }
      })}

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} geometry={boxGeo} material={hoverMaterial} />
             )}
         </group>
      )}

      {/* Base Plane for Raycasting */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[40, 40]} />
      </mesh>

      {currentType === ShapeType.HEX ? (
           <gridHelper args={[20, 20, 0x444444, 0x111111]} position={[0, -0.01, 0]} />
      ) : (
           <gridHelper args={[20, 20, 0x444444, 0x222222]} position={[0, -0.5, 0]} />
      )}

    </group>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
