import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FEEDING MECHANICS
  private readonly MAGNET_RADIUS = 1.5; // Reduced: Requires head to be close
  private readonly MAGNET_FORCE = 0.4;  // Strong pull only when very close
  private readonly EAT_RADIUS = 0.4;    // Precision eating

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;
  private onNewGenerationCallback: ((pop: Organism[]) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep clone to ensure we sever references to the old simulation loop.
      // We use a replacer to safely handle any potential circular refs (like brain -> organism)
      // even though inputs *should* be clean, safety first.
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); // false = don't reset generation to 1
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          // First one is a pure clone (Elite), others are mutated
          if (i > 0) {
              this.mutateGenome(child.neuralGenome);
          }

          // Spawn Food Track for this creature
          child.visibleFood = this.generateFoodTrack(child);

          this.population.push(child);
      }

      if (this.onNewGenerationCallback) {
          this.onNewGenerationCallback(this.population);
      }
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = 40; // Abundant food to stimulate "Tree" environment

      // Level Design: "The Canopy"
      // Instead of a path, create a cloud of food around the creature's HEAD.
      // Encourages: Balancing, Reaching, Standing Up, Neck Control.

      let centerX = 0;
      let centerZ = 0;

      // Find the head to center the food cloud
      const head = organism.nodes.find(n => n.isHead);
      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      for(let i=0; i<numFood; i++) {
          // Random spherical/cylindrical distribution around HEAD
          const theta = Math.random() * Math.PI * 2;

          // Distance: Close enough to reach if leaning (0.8), far enough to need steps (3.0)
          const radius = 0.8 + Math.random() * 2.2; 

          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;

          // Verticality: 
          // 1.0 = Low Hanging Fruit (Chin level)
          // 3.5 = High Fruit (Must stand/jump)
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      // Sort by fitness temporarily to find best
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      // Return a clean clone without the BrainController instance
      // FIX: Use replacer to break circular dependency (brain -> organism -> brain)
      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);

      // Ensure current generation is saved in the organism so we can resume
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    // AUTO-CYCLE: If everyone is dead, start next generation automatically
    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.15; 

      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt;

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);

          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          if (!org.isAlive) return;

          // 1. HUNGER CALCULATIONS
          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              this.calculateFitness(org); 
          }

          // 2. EATING LOGIC (With Magnetism)
          const head = org.nodes.find(n => n.isHead);
          if (!head) return; 

          // Check visible food
          let checkCount = 0;
          for (const food of org.visibleFood) {
              if (food.consumed) continue;
              if (checkCount++ > 10) break; // Check nearest 10 (optimization)

              const dist = VectorOps.distance(head.pos, food.pos);

              // MAGNET EFFECT: Pull food in if close
              if (dist < this.MAGNET_RADIUS) {
                  // Interpolate food position towards head
                  const pull = VectorOps.sub(head.pos, food.pos);
                  // Apply lerp
                  food.pos.x += pull.x * this.MAGNET_FORCE;
                  food.pos.y += pull.y * this.MAGNET_FORCE;
                  food.pos.z += pull.z * this.MAGNET_FORCE;

                  // EAT
                  if (dist < this.EAT_RADIUS) {
                      food.consumed = true;
                      org.energy += food.energyValue;
                      if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                      org.hungerTime = 0;
                      org.foodEaten++;
                  }
              }
          }
      });
  }

  private calculateFitness(org: Organism) {
      // GOAL: Eat Food + Maintain Height
      // Distance (Z) is NO LONGER relevant.

      let headY = 0;
      const head = org.nodes.find(n => n.isHead);
      if (head) headY = head.pos.y;

      // Heavy weight on eating
      // Secondary weight on standing tall (helps them reach next fruit)
      org.fitness = (org.foodEaten * 100.0) + (Math.max(0, headY) * 10.0);
  }

  private finalizeFitness() {
      this.population.forEach(org => this.calculateFitness(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    // Notification: Generation Complete (Stats)
    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);
      this.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    // Notification: New Population Ready
    if (this.onNewGenerationCallback) {
        this.onNewGenerationCallback(this.population);
    }
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // Robust clone that ignores circular references
      const safeJson = JSON.stringify(template, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const clone: Organism = JSON.parse(safeJson);

      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; 

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                arr[i] += (Math.random() - 0.5) * 0.5;
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };
    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.onNewGenerationCallback = cb; }
}

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat
  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // Biases for neurons
  biases: number[];
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Distance traveled
  generation: number;

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number; 
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const numMuscles = muscles.length;
    const reservoirSize = 20;

    const genome: NeuralGenome = {
        synapseWeights: this.randomArray(numMuscles * 2),
        reservoirWeights: this.randomArray(reservoirSize * reservoirSize),
        outputWeights: this.randomArray(numMuscles * reservoirSize),
        biases: this.randomArray(nodes.length)
    };

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Updated Heuristic: Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | null = null;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: []
    };
  }

  private static randomArray(size: number): number[] {
      return Array.from({ length: size }, () => (Math.random() * 1.0) - 0.5); 
  }

  private static createTetrahedron() {
    const f = 0.95; // High friction for grip
    const m = 4.0;  // Heavy mass

    const nodes: Node[] = [
      { id: 'n1', pos: { x: 0, y: 0, z: 1 }, oldPos: { x: 0, y: 0, z: 1 }, mass: m, friction: f },
      { id: 'n2', pos: { x: 1, y: 0, z: -0.7 }, oldPos: { x: 1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n3', pos: { x: -1, y: 0, z: -0.7 }, oldPos: { x: -1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n4', pos: { x: 0, y: 1.5, z: 0 }, oldPos: { x: 0, y: 1.5, z: 0 }, mass: m, friction: f },
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push({
            id: `n${x}${y}${z}`,
            pos: { x: px, y: py, z: pz },
            oldPos: { x: px, y: py, z: pz },
            mass: m, 
            friction: f
          });
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; // Belly slides a bit
    const footFriction = 0.98; // Feet grip hard
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            { id: `n${i}_a`, pos: { x: -0.5, y: 0, z: offset }, oldPos: { x: -0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_b`, pos: { x: 0.5, y: 0, z: offset }, oldPos: { x: 0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_top`, pos: { x: 0, y: 1, z: offset + 0.5 }, oldPos: { x: 0, y: 1, z: offset + 0.5 }, mass: m, friction: bellyFriction }
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, // Maximum stiffness for bones
          dnaIndex: 0,
          // Init Oscillator
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              // Init Oscillator
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
            });
          }
        }
      }
      return muscles;
    }
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
    // We no longer clear() here. 
    // This allows the user to view the same voxel data interpreted through different lattices.
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();

      // Strategy: The "Stable Walker"
      // 10-15 voxels. 
      // Strong focus on Ground Contact and Central Mass.

      const length = 4 + Math.floor(rng() * 3); // 4 to 6 long
      const wideStance = rng() > 0.4; // 60% chance of wide legs
      const legX = wideStance ? 2 : 1;

      // 1. Central Spine (Chassis)
      // Raised off ground (y=1) to allow leg movement
      for(let z=0; z<length; z++) {
          this.setCell(0, 1, z, true);
      }

      // 2. Head (Front + Center + High)
      // Always at the very front (max Z)
      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);

      // NEW: 50% chance to grow a Neck (Y=3) to reach high food
      if (rng() > 0.5) {
          this.setCell(0, 3, headZ, true);
      }

      // 3. Legs (Stabilizers)
      // We place legs at the rear and near the front (but behind head)
      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          // Foot on ground
          this.setCell(legX, 0, z, true);
          // Knee/Hip connector to spine
          this.setCell(1, 1, z, true);

          // If very wide, need an intermediate strut for stability
          if (legX === 2) {
              this.setCell(1, 0, z, true); // Block under the hip
          }
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      // 4. Body Mass / Ribs
      // Add a few random blocks to the side of the spine for structural integrity
      // Avoid "useless appendages" by keeping them attached to spine
      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) {
               this.setCell(1, 1, z, true);
           }
      }

      // 5. Apply Symmetry
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    // Architecture Parameters
    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    // 1. Spine Core (The backbone)
    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        // Central Bone
        this.setCell(0, bodyHeight, absZ, true);

        // Ribcage/Bulk (60% chance to add block above or below for volume)
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    // 2. Limbs (Procedural "Growth")
    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;

        // Path to ground
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        // Shoulder
        cx++;
        this.setCell(cx, cy, cz, true);

        // Grow down to floor
        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        // Foot Pad
        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    // 3. Head (Front +Z)
    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    // Neck extension
    this.setCell(0, bodyHeight - 1, headZ, true);

    // 4. Apply Symmetry
    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      // Random Walk
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;

          // Bounds check roughly
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              // Simple X mirroring for Axial coordinates is tricky, 
              // but purely flipping 'x' (q) often works for visual symmetry 
              // depending on orientation.
              const mx = -x;
              newCells.set(`${mx},${y},${z}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  // --- IMPORT FROM ORGANISM (Reverse Engineering) ---

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; // Fallback if old save

      const scale = 0.8;

      for (const node of org.nodes) {
          const px = node.pos.x;
          const py = node.pos.y;
          const pz = node.pos.z;

          let gx = 0, gy = 0, gz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6;
              const hexHeight = scale * 0.7;

              // Inverse Axial
              const q = px / (size * 1.5);
              const r = (pz / (size * Math.sqrt(3))) - q/2;
              const y = (py - 0.5) / hexHeight;

              gx = Math.round(q);
              gy = Math.round(y);
              gz = Math.round(r);
          } else if (this.type === ShapeType.TETRAHEDRON) {
              // Y Logic
              const y = (py - 0.5) / (scale * 0.82);
              gy = Math.round(y);

              // Offset based on odd/even row
              const isOdd = gy % 2 !== 0;
              const offset = isOdd ? scale * 0.5 : 0;

              const x = (px - offset) / scale;
              const z = (pz - offset) / scale;

              gx = Math.round(x);
              gz = Math.round(z);
          } else {
              // CUBE / WORM (Default)
              gx = Math.round(px / scale);
              gy = Math.round((py - 0.5) / scale);
              gz = Math.round(pz / scale);
          }

          this.setCell(gx, gy, gz, true);
      }
  }

  // --- EXPORT TO PHYSICS ---

  public generateOrganism(id: string): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // 1. Create Nodes
      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c, i) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          if (this.type === ShapeType.HEX) {
              // 3D Hex Prism logic
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;

              // Standard Flat-topped or Pointy-topped conversion
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);

              // Vertical Stacking
              const hexHeight = scale * 0.7; // Slightly shorter than wide for stability
              py = 0.5 + c.y * hexHeight; 

          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = c.y * (scale * 0.82) + 0.5;
          } else {
              // CUBE
              px = c.x * scale;
              py = c.y * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);

      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });

      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);

      let headNode: Node | null = null;
      let minAbsX = Infinity;

      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // 3. Create Muscles (Connections)
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              // --- HORIZONTAL NEIGHBORS (6 directions) ---
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- VERTICAL NEIGHBORS (Up/Down) ---
              // This turns the flat sheet into a 3D Honeycomb Prism structure
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- CROSS BRACING (Optional but good for rigidity) ---
              // Connect (x,y,z) to neighbors at (y+1) or (y-1) for diagonal strength
              // Only simple diagonals for now to avoid clutter
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [
                  {dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0},
                  {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0},
                  {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1},
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [
                  {dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0},
                  {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1},
                  {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}
              ];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      return {
          id,
          shape: this.type, // Store type
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: 0,
          generation: 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  // Ref for synchronous access inside tight loops
  const isAutoEvolvingRef = useRef(false);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [bestFitness, setBestFitness] = useState(0);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.TETRAHEDRON);
  const [isRunning, setIsRunning] = useState(false);
  const [isAutoEvolving, setIsAutoEvolvingState] = useState(false);

  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    service.onUpdate((pop) => {
        // We do NOT set state here every frame to avoid React render thrashing.
    });

    service.onGenComplete((best, gen) => {
        setBestFitness(best.fitness);
        setGeneration(gen);
    });

    // NEW: Sync population when EvolutionService triggers an evolution internally
    service.onNewGeneration((newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => cancelAnimationFrame(requestRef.current!);
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);

    // Stop Auto
    isAutoEvolvingRef.current = false;
    setIsAutoEvolvingState(false);

    setIsProcessing(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    setBestFitness(0);
  }, []);

  const spawnCustom = useCallback((organism: Organism) => {
      setIsRunning(false);
      isAutoEvolvingRef.current = false;
      setIsAutoEvolvingState(false);
      setIsProcessing(false);

      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      setBestFitness(0);
      setCurrentShape(ShapeType.WORM); 
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              // Stop everything
              setIsRunning(false);
              isAutoEvolvingRef.current = false;
              setIsAutoEvolvingState(false);
              setIsProcessing(false);

              // Inject
              const startGen = organism.generation || 1;
              serviceRef.current.setTemplateAndReset(organism, startGen);

              setPopulation([...serviceRef.current.population]);
              setGeneration(startGen);
              setBestFitness(0);

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, []);


  // --- AUTO EVOLUTION ---

  const runAutoEvolution = useCallback(async () => {
      if (isProcessing) return; // Prevent double entry

      setIsProcessing(true);

      try {
          // 1. Compute Generation Async (Yielding to UI)
          // We pass a callback that checks our Ref. If ref is false, service throws error.
          await serviceRef.current.computeGenerationAsync(
              10.0, 
              () => !isAutoEvolvingRef.current, // Stop Signal
              (pct) => setProgress(pct)
          );

          // 2. Evolve (Only if we finished successfully)
          evolve();

          // 3. Reset for next round
          setProgress(0);
          setIsProcessing(false);

      } catch (e) {
          // If we aborted (or other error), we catch it here.
          console.log("Evolution Stopped or Aborted");
          setIsProcessing(false);
          // Do NOT evolve. We stay on the current generation.
      }
  }, [isProcessing, evolve]);

  const toggleAutoEvolve = useCallback(() => {
      const newState = !isAutoEvolvingRef.current;
      isAutoEvolvingRef.current = newState;
      setIsAutoEvolvingState(newState);

      // If turning ON, ensure regular run is off (optional, but cleaner)
      if (newState) setIsRunning(false);
  }, []);

  const loop = useCallback(() => {
    // If neither running nor auto, stop loop
    if (!isRunning && !isAutoEvolving) return;

    if (isAutoEvolving) {
        if (!isProcessing) {
            runAutoEvolution();
        }
        // While processing, we do nothing in this loop (we wait for async in runAutoEvolution)
    } else {
        // NORMAL MODE: 60 FPS Physics
        if (isRunning) {
            serviceRef.current.step(0.016);
        }
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isAutoEvolving, isProcessing, runAutoEvolution]);

  useEffect(() => {
    if (isRunning || isAutoEvolving) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, isAutoEvolving, loop]);

  return {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing, 
    progress,    
    currentShape,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  };
}

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { LabScene } from './src/infrastructure/visuals/LabScene';
import { Dashboard } from './src/ui/Dashboard';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintViewUpdated } from './src/infrastructure/visuals/BlueprintView';
import { ArchitectControls } from './src/ui/ArchitectControls';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType } from './src/domain/types';

function App() {
  const {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing,
    progress,
    currentShape,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  const [mode, setMode] = useState<'LAB' | 'ARCHITECT'>('LAB');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // Architect State
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [archType, setArchType] = useState(ShapeType.CUBE);

  // --- HANDLERS ---

  const handleLoad = (file: File) => {
      loadCreature(file, (org) => {
          // Sync Architect State
          blueprintService.importOrganism(org);
          setBlueprintCells(blueprintService.getCells());
          setArchType(org.shape || ShapeType.CUBE);
      });
  };

  const handleArchCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      if (isRight) {
          blueprintService.setCell(x, y, z, false);
      } else {
          blueprintService.setCell(x, y, z, true);
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchGenerate = (type: string) => {
      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'procedural') blueprintService.generateLargeBeast(); // Legacy Fallback

      if (type === 'floor') blueprintService.applyFloorFill();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchType = (t: ShapeType) => {
      setArchType(t);
      blueprintService.setType(t);
      // We do NOT clear cells here anymore, so the form persists.
      // But we must update the state to force a re-render of the View
      setBlueprintCells([...blueprintService.getCells()]);
  };

  const handleSpawn = () => {
      const organism = blueprintService.generateOrganism('custom_proto');
      spawnCustom(organism);
      setMode('LAB');
  };

  return (
    <div className="relative w-full h-full bg-slate-900">

      {/* MODE TOGGLE */}
      <div className="absolute top-4 right-1/2 translate-x-1/2 z-10 flex bg-slate-800 rounded-full p-1 border border-slate-700">
          <button 
            onClick={() => setMode('LAB')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'LAB' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              LAB
          </button>
          <button 
            onClick={() => setMode('ARCHITECT')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'ARCHITECT' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              ARCHITECT
          </button>
      </div>

      {mode === 'LAB' ? (
          <>
            <LabScene 
                population={population} 
                showBestOnly={showBestOnly}
            />
            <Dashboard 
                generation={generation}
                bestFitness={bestFitness}
                isRunning={isRunning}
                isAutoEvolving={isAutoEvolving}
                isProcessing={isProcessing}
                progress={progress}
                currentShape={currentShape}
                onReset={reset}
                onToggleRun={() => setIsRunning(!isRunning)}
                onToggleAutoEvolve={toggleAutoEvolve} 
                showBestOnly={showBestOnly}
                setShowBestOnly={setShowBestOnly}
                onSave={saveCreature}
                onLoad={handleLoad}
            />
            {/* Instruction Toast */}
            {!isRunning && generation === 1 && !isAutoEvolving && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-black/50 text-white px-4 py-2 rounded-full backdrop-blur text-sm pointer-events-none animate-pulse">
                    Press RESUME to start the simulation
                </div>
            )}
          </>
      ) : (
          <>
            {/* ARCHITECT 3D VIEW */}
            <div className="w-full h-full cursor-crosshair">
                <Canvas shadows dpr={[1, 2]}>
                    <PerspectiveCamera makeDefault position={[8, 8, 8]} fov={45} />
                    <OrbitControls makeDefault target={[0, 0, 0]} />
                    <BlueprintViewUpdated
                        cells={blueprintCells} 
                        onCellClick={handleArchCellClick}
                        currentType={archType}
                    />
                </Canvas>
            </div>

            <ArchitectControls 
                onClear={() => { blueprintService.clear(); setBlueprintCells([]); }}
                onSetType={handleArchType}
                onGenerate={handleArchGenerate}
                onSpawn={handleSpawn}
                currentType={archType}
                cellCount={blueprintCells.length}
            />
          </>
      )}

    </div>
  );
}

export default App;

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // Biases for neurons
  biases: number[];
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Distance traveled
  generation: number;

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number; 
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
    // We no longer clear() here. 
    // This allows the user to view the same voxel data interpreted through different lattices.
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();

      // Strategy: The "Stable Walker"
      // 10-15 voxels. 
      // Strong focus on Ground Contact and Central Mass.

      const length = 4 + Math.floor(rng() * 3); // 4 to 6 long
      const wideStance = rng() > 0.4; // 60% chance of wide legs
      const legX = wideStance ? 2 : 1;

      // 1. Central Spine (Chassis)
      // Raised off ground (y=1) to allow leg movement
      for(let z=0; z<length; z++) {
          this.setCell(0, 1, z, true);
      }

      // 2. Head (Front + Center + High)
      // Always at the very front (max Z)
      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);

      // NEW: 50% chance to grow a Neck (Y=3) to reach high food
      if (rng() > 0.5) {
          this.setCell(0, 3, headZ, true);
      }

      // 3. Legs (Stabilizers)
      // We place legs at the rear and near the front (but behind head)
      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          // Foot on ground
          this.setCell(legX, 0, z, true);
          // Knee/Hip connector to spine
          this.setCell(1, 1, z, true);

          // If very wide, need an intermediate strut for stability
          if (legX === 2) {
              this.setCell(1, 0, z, true); // Block under the hip
          }
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      // 4. Body Mass / Ribs
      // Add a few random blocks to the side of the spine for structural integrity
      // Avoid "useless appendages" by keeping them attached to spine
      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) {
               this.setCell(1, 1, z, true);
           }
      }

      // 5. Apply Symmetry
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    // Architecture Parameters
    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    // 1. Spine Core (The backbone)
    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        // Central Bone
        this.setCell(0, bodyHeight, absZ, true);

        // Ribcage/Bulk (60% chance to add block above or below for volume)
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    // 2. Limbs (Procedural "Growth")
    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;

        // Path to ground
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        // Shoulder
        cx++;
        this.setCell(cx, cy, cz, true);

        // Grow down to floor
        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        // Foot Pad
        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    // 3. Head (Front +Z)
    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    // Neck extension
    this.setCell(0, bodyHeight - 1, headZ, true);

    // 4. Apply Symmetry
    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      // Random Walk
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;

          // Bounds check roughly
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              // Simple X mirroring for Axial coordinates is tricky, 
              // but purely flipping 'x' (q) often works for visual symmetry 
              // depending on orientation.
              const mx = -x;
              newCells.set(`${mx},${y},${z}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  // --- IMPORT FROM ORGANISM (Reverse Engineering) ---

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      // 1. PREFERRED METHOD: Use stored editor metadata
      let hasMetadata = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              hasMetadata = true;
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }

      if (hasMetadata) return;

      // 2. FALLBACK METHOD: Reverse engineering (Lossy)
      const scale = 0.8;

      for (const node of org.nodes) {
          const px = node.pos.x;
          const py = node.pos.y;
          const pz = node.pos.z;

          let gx = 0, gy = 0, gz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6;
              const hexHeight = scale * 0.7;

              const q = px / (size * 1.5);
              const r = (pz / (size * Math.sqrt(3))) - q/2;
              const y = (py - 0.5) / hexHeight;

              gx = Math.round(q);
              gy = Math.round(y);
              gz = Math.round(r);
          } else if (this.type === ShapeType.TETRAHEDRON) {
              const y = (py - 0.5) / (scale * 0.82);
              gy = Math.round(y);

              const isOdd = gy % 2 !== 0;
              const offset = isOdd ? scale * 0.5 : 0;

              const x = (px - offset) / scale;
              const z = (pz - offset) / scale;

              gx = Math.round(x);
              gz = Math.round(z);
          } else {
              // CUBE / WORM (Default)
              gx = Math.round(px / scale);
              gy = Math.round((py - 0.5) / scale);
              gz = Math.round(pz / scale);
          }

          this.setCell(gx, gy, gz, true);
      }
  }

  // --- EXPORT TO PHYSICS ---

  public generateOrganism(id: string): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // 1. Create Nodes
      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c, i) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          if (this.type === ShapeType.HEX) {
              // 3D Hex Prism logic
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;

              // Standard Flat-topped or Pointy-topped conversion
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);

              // Vertical Stacking
              const hexHeight = scale * 0.7; // Slightly shorter than wide for stability
              py = 0.5 + c.y * hexHeight; 

          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = c.y * (scale * 0.82) + 0.5;
          } else {
              // CUBE
              px = c.x * scale;
              py = c.y * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction,
              // IMPORTANT: Save the source grid coordinate to allow perfect reloading
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // 2. Identify Head
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);

      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });

      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);

      let headNode: Node | null = null;
      let minAbsX = Infinity;

      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });

      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // 3. Create Muscles (Connections)
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              // --- HORIZONTAL NEIGHBORS (6 directions) ---
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- VERTICAL NEIGHBORS (Up/Down) ---
              // This turns the flat sheet into a 3D Honeycomb Prism structure
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });

              // --- CROSS BRACING (Optional but good for rigidity) ---
              // Connect (x,y,z) to neighbors at (y+1) or (y-1) for diagonal strength
              // Only simple diagonals for now to avoid clutter
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [
                  {dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0},
                  {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0},
                  {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1},
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [
                  {dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0},
                  {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1},
                  {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}
              ];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      return {
          id,
          shape: this.type, // Store type
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: 0,
          generation: 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FEEDING MECHANICS
  private readonly MAGNET_RADIUS = 1.5; // Reduced: Requires head to be close
  private readonly MAGNET_FORCE = 0.4;  // Strong pull only when very close
  private readonly EAT_RADIUS = 0.4;    // Precision eating

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;
  private onNewGenerationCallback: ((pop: Organism[]) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep clone to ensure we sever references to the old simulation loop.
      // We use a replacer to safely handle any potential circular refs (like brain -> organism)
      // even though inputs *should* be clean, safety first.
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); // false = don't reset generation to 1
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          // First one is a pure clone (Elite), others are mutated
          if (i > 0) {
              this.mutateGenome(child.neuralGenome);
          }

          // Spawn Food Track for this creature
          child.visibleFood = this.generateFoodTrack(child);

          this.population.push(child);
      }

      if (this.onNewGenerationCallback) {
          this.onNewGenerationCallback(this.population);
      }
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = 40; // Abundant food to stimulate "Tree" environment

      // Level Design: "The Canopy"
      // Instead of a path, create a cloud of food around the creature's HEAD.
      // Encourages: Balancing, Reaching, Standing Up, Neck Control.

      let centerX = 0;
      let centerZ = 0;

      // Find the head to center the food cloud
      const head = organism.nodes.find(n => n.isHead);
      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      for(let i=0; i<numFood; i++) {
          // Random spherical/cylindrical distribution around HEAD
          const theta = Math.random() * Math.PI * 2;

          // Distance: Close enough to reach if leaning (0.8), far enough to need steps (3.0)
          const radius = 0.8 + Math.random() * 2.2; 

          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;

          // Verticality: 
          // 1.0 = Low Hanging Fruit (Chin level)
          // 3.5 = High Fruit (Must stand/jump)
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      // Sort by fitness temporarily to find best
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      // Return a clean clone without the BrainController instance
      // FIX: Use replacer to break circular dependency (brain -> organism -> brain)
      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);

      // Ensure current generation is saved in the organism so we can resume
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    // AUTO-CYCLE: If everyone is dead, start next generation automatically
    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 

      // FIX: Reduce Batch Duration significantly to yield to UI thread
      // 12ms allows ample time for 60fps frame budget (16ms)
      const BATCH_DURATION = 0.012; 

      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;

          // INNER LOOP: Run physics until batch time budget is exceeded
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; // Actual wall clock time estimate

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);

          // Yield to event loop immediately to handle clicks/render
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          if (!org.isAlive) return;

          // 1. HUNGER CALCULATIONS
          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              this.calculateFitness(org); 
          }

          // 2. EATING LOGIC (With Magnetism)
          const head = org.nodes.find(n => n.isHead);
          if (!head) return; 

          // Check visible food
          let checkCount = 0;
          for (const food of org.visibleFood) {
              if (food.consumed) continue;
              if (checkCount++ > 10) break; // Check nearest 10 (optimization)

              const dist = VectorOps.distance(head.pos, food.pos);

              // MAGNET EFFECT: Pull food in if close
              if (dist < this.MAGNET_RADIUS) {
                  // Interpolate food position towards head
                  const pull = VectorOps.sub(head.pos, food.pos);
                  // Apply lerp
                  food.pos.x += pull.x * this.MAGNET_FORCE;
                  food.pos.y += pull.y * this.MAGNET_FORCE;
                  food.pos.z += pull.z * this.MAGNET_FORCE;

                  // EAT
                  if (dist < this.EAT_RADIUS) {
                      food.consumed = true;
                      org.energy += food.energyValue;
                      if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                      org.hungerTime = 0;
                      org.foodEaten++;
                  }
              }
          }
      });
  }

  private calculateFitness(org: Organism) {
      // GOAL: Eat Food + Maintain Height
      // Distance (Z) is NO LONGER relevant.

      let headY = 0;
      const head = org.nodes.find(n => n.isHead);
      if (head) headY = head.pos.y;

      // Heavy weight on eating
      // Secondary weight on standing tall (helps them reach next fruit)
      org.fitness = (org.foodEaten * 100.0) + (Math.max(0, headY) * 10.0);
  }

  private finalizeFitness() {
      this.population.forEach(org => this.calculateFitness(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    // Notification: Generation Complete (Stats)
    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);
      this.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    // Notification: New Population Ready
    if (this.onNewGenerationCallback) {
        this.onNewGenerationCallback(this.population);
    }
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // Robust clone that ignores circular references
      const safeJson = JSON.stringify(template, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const clone: Organism = JSON.parse(safeJson);

      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; 

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                arr[i] += (Math.random() - 0.5) * 0.5;
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };
    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.onNewGenerationCallback = cb; }
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              // --- HEX SYMMETRY FIX ---
              // Axial Coordinates: q, r
              // Mirror across X-axis (Vertical line through center):
              // q' = -q
              // r' = r + q
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             // Standard Cartesian
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      let hasMetadata = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              hasMetadata = true;
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }

      if (hasMetadata) return;

      const scale = 0.8;
      for (const node of org.nodes) {
          const px = node.pos.x;
          const py = node.pos.y;
          const pz = node.pos.z;

          let gx = 0, gy = 0, gz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6;
              const hexHeight = scale * 0.7;
              const q = px / (size * 1.5);
              const r = (pz / (size * Math.sqrt(3))) - q/2;
              const y = (py - 0.5) / hexHeight;
              gx = Math.round(q);
              gy = Math.round(y);
              gz = Math.round(r);
          } else if (this.type === ShapeType.TETRAHEDRON) {
              const y = (py - 0.5) / (scale * 0.82);
              gy = Math.round(y);
              const isOdd = gy % 2 !== 0;
              const offset = isOdd ? scale * 0.5 : 0;
              const x = (px - offset) / scale;
              const z = (pz - offset) / scale;
              gx = Math.round(x);
              gz = Math.round(z);
          } else {
              gx = Math.round(px / scale);
              gy = Math.round((py - 0.5) / scale);
              gz = Math.round(pz / scale);
          }
          this.setCell(gx, gy, gz, true);
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);
              const hexHeight = scale * 0.7; 
              py = 0.5 + c.y * hexHeight; 
          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = c.y * (scale * 0.82) + 0.5;
          } else {
              px = c.x * scale;
              py = c.y * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // Head Logic
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);
      let headNode: Node | null = null;
      let minAbsX = Infinity;
      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });
      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // Muscle Creation
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [{dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0}, {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0}, {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1}];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [{dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0}, {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1}, {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome Init
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      // --- BRAIN GRAFTING ---
      // If we have a source, we try to preserve knowledge
      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          const oldMuscles = source.muscles;
          const oldNodes = source.nodes;

          // A. Copy Reservoir (Central Pattern Generator)
          if (oldGenome.reservoirWeights.length === genome.reservoirWeights.length) {
              genome.reservoirWeights = [...oldGenome.reservoirWeights];
          }

          // B. Copy Synapses (Muscle-Specific Memory)
          muscles.forEach((newM, i) => {
              // Try to find a muscle connecting the same grid coordinates
              // Muscle ID is based on Grid coords: "m_n_0_0_0-n_0_1_0"
              const match = oldMuscles.find(om => om.id === newM.id);
              if (match) {
                  // Found matching limb! Graft the weights.
                  const oldIdx = match.dnaIndex || 0;
                  const newIdx = i;

                  // Copy input weights (Synapse Weights are array of size * 2?)
                  // In BrainController, it's: synapseWeights[i % length]
                  // Actually NeuralGenome defines it as number[].
                  // Let's assume 1:1 mapping for simplicity of the graft.

                  if (oldGenome.synapseWeights[oldIdx] !== undefined) {
                      genome.synapseWeights[newIdx] = oldGenome.synapseWeights[oldIdx];
                  }

                  // Copy Output Weights (CPG -> Muscle)
                  // outputWeights size = numMuscles * reservoirSize
                  // We need to copy the slice corresponding to this muscle
                  const startOld = oldIdx * reservoirSize;
                  const startNew = newIdx * reservoirSize;

                  for(let k=0; k<reservoirSize; k++) {
                      if (oldGenome.outputWeights[startOld+k] !== undefined) {
                          genome.outputWeights[startNew+k] = oldGenome.outputWeights[startOld+k];
                      }
                  }
              }
          });

          // C. Copy Biases (Node-Specific Memory)
          nodes.forEach((newN, i) => {
              const match = oldNodes.find(on => on.id === newN.id);
              if (match) {
                  // Find index in old array?
                  // Biases are simple array aligned with nodes.
                  const oldNodeIdx = oldNodes.findIndex(on => on.id === newN.id);
                  if (oldNodeIdx !== -1 && oldGenome.biases[oldNodeIdx] !== undefined) {
                      genome.biases[i] = oldGenome.biases[oldNodeIdx];
                  }
              }
          });
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0, // Keep fitness? Maybe reset fitness but keep generation.
          generation: source ? source.generation : 1, // Keep generation count
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

import React, { useState, useRef, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera } from '@react-three/drei';
import { LabScene } from './src/infrastructure/visuals/LabScene';
import { Dashboard } from './src/ui/Dashboard';
import { useEvolutionLoop } from './src/application/useEvolutionLoop';
import { BlueprintViewUpdated } from './src/infrastructure/visuals/BlueprintView';
import { ArchitectControls } from './src/ui/ArchitectControls';
import { BlueprintService } from './src/domain/BlueprintService';
import { ShapeType, Organism } from './src/domain/types';

function App() {
  const {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing,
    progress,
    currentShape,
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  } = useEvolutionLoop();

  const [mode, setMode] = useState<'LAB' | 'ARCHITECT'>('LAB');
  const [showBestOnly, setShowBestOnly] = useState(false);

  // Architect State
  const blueprintService = useMemo(() => new BlueprintService(), []);
  const [blueprintCells, setBlueprintCells] = useState(blueprintService.getCells());
  const [archType, setArchType] = useState(ShapeType.CUBE);

  // TRACKING FOR EDITING
  const [editingOrganism, setEditingOrganism] = useState<Organism | undefined>(undefined);

  // --- HANDLERS ---

  const handleLoad = (file: File) => {
      loadCreature(file, (org) => {
          // Sync Architect State
          blueprintService.importOrganism(org);
          setBlueprintCells(blueprintService.getCells());
          setArchType(org.shape || ShapeType.CUBE);

          // Store for potential editing
          setEditingOrganism(org);
      });
  };

  const handleArchCellClick = (x: number, y: number, z: number, isRight: boolean) => {
      if (isRight) {
          blueprintService.setCell(x, y, z, false);
      } else {
          blueprintService.setCell(x, y, z, true);
      }
      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchGenerate = (type: string) => {
      // If we generate a new random template, we clear the "editing" link
      // unless we want to merge? For now, assume fresh start.
      setEditingOrganism(undefined);

      if (type === 'small') blueprintService.generateSmallCritter();
      if (type === 'large') blueprintService.generateLargeBeast();
      if (type === 'procedural') blueprintService.generateLargeBeast(); 

      if (type === 'floor') blueprintService.applyFloorFill();
      if (type === 'worm') blueprintService.applyWorm(8);
      if (type === 'mirror') blueprintService.applyMirrorX();

      setBlueprintCells(blueprintService.getCells());
  };

  const handleArchType = (t: ShapeType) => {
      setArchType(t);
      blueprintService.setType(t);
      setBlueprintCells([...blueprintService.getCells()]);
  };

  const handleSpawn = () => {
      // Pass editingOrganism as source to preserve brain
      const organism = blueprintService.generateOrganism('custom_proto', editingOrganism);
      spawnCustom(organism);
      setMode('LAB');
  };

  const handleClear = () => {
      blueprintService.clear();
      setBlueprintCells([]);
      setEditingOrganism(undefined);
  };

  return (
    <div className="relative w-full h-full bg-slate-900">

      {/* MODE TOGGLE */}
      <div className="absolute top-4 right-1/2 translate-x-1/2 z-10 flex bg-slate-800 rounded-full p-1 border border-slate-700">
          <button 
            onClick={() => setMode('LAB')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'LAB' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              LAB
          </button>
          <button 
            onClick={() => setMode('ARCHITECT')}
            className={`px-4 py-1 rounded-full text-xs font-bold transition-all ${mode === 'ARCHITECT' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
          >
              ARCHITECT
          </button>
      </div>

      {mode === 'LAB' ? (
          <>
            <LabScene 
                population={population} 
                showBestOnly={showBestOnly}
            />
            <Dashboard 
                generation={generation}
                bestFitness={bestFitness}
                isRunning={isRunning}
                isAutoEvolving={isAutoEvolving}
                isProcessing={isProcessing}
                progress={progress}
                currentShape={currentShape}
                onReset={reset}
                onToggleRun={() => setIsRunning(!isRunning)}
                onToggleAutoEvolve={toggleAutoEvolve} 
                showBestOnly={showBestOnly}
                setShowBestOnly={setShowBestOnly}
                onSave={saveCreature}
                onLoad={handleLoad}
            />
            {/* Instruction Toast */}
            {!isRunning && generation === 1 && !isAutoEvolving && (
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 bg-black/50 text-white px-4 py-2 rounded-full backdrop-blur text-sm pointer-events-none animate-pulse">
                    Press RESUME to start the simulation
                </div>
            )}
          </>
      ) : (
          <>
            {/* ARCHITECT 3D VIEW */}
            <div className="w-full h-full cursor-crosshair">
                <Canvas shadows dpr={[1, 2]}>
                    <PerspectiveCamera makeDefault position={[8, 8, 8]} fov={45} />
                    <OrbitControls makeDefault target={[0, 0, 0]} />
                    <BlueprintViewUpdated
                        cells={blueprintCells} 
                        onCellClick={handleArchCellClick}
                        currentType={archType}
                    />
                </Canvas>
            </div>

            <ArchitectControls 
                onClear={handleClear}
                onSetType={handleArchType}
                onGenerate={handleArchGenerate}
                onSpawn={handleSpawn}
                currentType={archType}
                cellCount={blueprintCells.length}
            />
          </>
      )}

    </div>
  );
}

export default App;

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      let hasMetadata = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              hasMetadata = true;
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }

      if (hasMetadata) return;

      const scale = 0.8;

      // Legacy Fallback: Detect Min Y to prevent floor-clipping
      let minY = Infinity;
      for (const node of org.nodes) {
          if (node.pos.y < minY) minY = node.pos.y;
      }

      // Normalize floor to 0
      const floorBias = (minY < 0.2) ? minY - 0.5 : 0; // If close to 0, assume it was based at 0.5 (y=0)

      for (const node of org.nodes) {
          const px = node.pos.x;
          // Shift down relative to estimated floor, then scale
          const py = node.pos.y;
          const pz = node.pos.z;

          let gx = 0, gy = 0, gz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6;
              const hexHeight = scale * 0.7;
              const q = px / (size * 1.5);
              const r = (pz / (size * Math.sqrt(3))) - q/2;
              const y = (py - 0.5) / hexHeight;
              gx = Math.round(q);
              gy = Math.round(y);
              gz = Math.round(r);
          } else if (this.type === ShapeType.TETRAHEDRON) {
              const y = (py - 0.5) / (scale * 0.82);
              gy = Math.round(y);
              const isOdd = gy % 2 !== 0;
              const offset = isOdd ? scale * 0.5 : 0;
              const x = (px - offset) / scale;
              const z = (pz - offset) / scale;
              gx = Math.round(x);
              gz = Math.round(z);
          } else {
              gx = Math.round(px / scale);
              // Simple conversion without complex normalization for CUBE as it's most common
              gy = Math.round((py - 0.5) / scale);
              gz = Math.round(pz / scale);
          }
          this.setCell(gx, gy, gz, true);
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      activeCoords.forEach(c => { if(c.y < minY) minY = c.y; });
      const heightOffset = -minY; // e.g. if min is -2, add 2. if min is 5, subtract 5? No, align bottom to 0.

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          // Apply height shift to Physics Y only
          const yLevel = c.y + heightOffset;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);
              const hexHeight = scale * 0.7; 
              py = 0.5 + yLevel * hexHeight; 
          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = yLevel * (scale * 0.82) + 0.5;
          } else {
              px = c.x * scale;
              py = yLevel * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // Head Logic
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);
      let headNode: Node | null = null;
      let minAbsX = Infinity;
      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });
      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // Muscle Creation
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [{dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0}, {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0}, {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1}];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [{dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0}, {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1}, {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome Init & Grafting (Unchanged logic, just keeping structure)
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          const oldMuscles = source.muscles;
          const oldNodes = source.nodes;

          if (oldGenome.reservoirWeights.length === genome.reservoirWeights.length) {
              genome.reservoirWeights = [...oldGenome.reservoirWeights];
          }

          muscles.forEach((newM, i) => {
              const match = oldMuscles.find(om => om.id === newM.id);
              if (match) {
                  const oldIdx = match.dnaIndex || 0;
                  const newIdx = i;
                  if (oldGenome.synapseWeights[oldIdx] !== undefined) {
                      genome.synapseWeights[newIdx] = oldGenome.synapseWeights[oldIdx];
                  }
                  const startOld = oldIdx * reservoirSize;
                  const startNew = newIdx * reservoirSize;
                  for(let k=0; k<reservoirSize; k++) {
                      if (oldGenome.outputWeights[startOld+k] !== undefined) {
                          genome.outputWeights[startNew+k] = oldGenome.outputWeights[startOld+k];
                      }
                  }
              }
          });

          nodes.forEach((newN, i) => {
              const match = oldNodes.find(on => on.id === newN.id);
              if (match) {
                  const oldNodeIdx = oldNodes.findIndex(on => on.id === newN.id);
                  if (oldNodeIdx !== -1 && oldGenome.biases[oldNodeIdx] !== undefined) {
                      genome.biases[i] = oldGenome.biases[oldNodeIdx];
                  }
              }
          });
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: []
      };
  }
}

import React, { useState, useMemo } from 'react';
import { useThree } from '@react-three/fiber';
import { GridCoord, ShapeType } from '../../domain/types';
import * as THREE from 'three';

// Helper to convert axial to pixel (for rendering hexes)
const hexToPixel = (q: number, r: number, size: number = 0.5) => {
    const x = size * 1.5 * q;
    const z = size * Math.sqrt(3) * (r + q/2);
    return { x, z };
};

// Neighbor directions for Hexagons (Axial)
const HEX_NEIGHBORS = [
    {q: 1, r: 0}, {q: 1, r: -1}, {q: 0, r: -1},
    {q: -1, r: 0}, {q: -1, r: 1}, {q: 0, r: 1}
];

export const BlueprintViewUpdated: React.FC<{
    cells: GridCoord[]; 
    onCellClick: (x: number, y: number, z: number, isRight: boolean) => void;
    currentType: ShapeType;
}> = ({ cells, onCellClick, currentType }) => {

  const { camera, raycaster, pointer, scene } = useThree();
  const [hoverCoord, setHoverCoord] = useState<GridCoord | null>(null);

  const boxGeo = useMemo(() => new THREE.BoxGeometry(0.8, 0.8, 0.8), []);
  const hexGeo = useMemo(() => new THREE.CylinderGeometry(0.45, 0.45, 0.5, 6), []); // Taller prism

  const material = useMemo(() => new THREE.MeshStandardMaterial({ color: '#3b82f6', roughness: 0.3 }), []);
  const materialHex = useMemo(() => new THREE.MeshStandardMaterial({ color: '#8b5cf6', roughness: 0.3 }), []);

  const hoverMaterial = useMemo(() => new THREE.MeshStandardMaterial({ color: '#facc15', transparent: true, opacity: 0.5 }), []);

  const handlePointerMove = (e: any) => {
      raycaster.setFromCamera(pointer, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      let hitPoint: THREE.Vector3 | null = null;
      let hitNormal: THREE.Vector3 | null = null;
      let hitObject: THREE.Object3D | null = null;

      for (const hit of intersects) {
          if (hit.object.name.startsWith('voxel') || hit.object.name === 'base_plane') {
              hitPoint = hit.point;
              hitNormal = hit.face?.normal || new THREE.Vector3(0,1,0);
              hitObject = hit.object;
              break;
          }
      }

      if (hitPoint) {
          if (currentType === ShapeType.HEX) {
              // --- HEX LOGIC ---
              if (hitObject?.name === 'voxel_hex') {
                  const data = hitObject.userData as GridCoord;

                  const relX = hitPoint.x - hitObject.position.x;
                  const relY = hitPoint.y - hitObject.position.y;
                  const relZ = hitPoint.z - hitObject.position.z;

                  // 1. Vertical Stacking (Top/Bottom Faces)
                  // The Cylinder is 0.5 high. So Top is ~0.25, Bottom ~ -0.25
                  if (relY > 0.23) {
                      setHoverCoord({ x: data.x, y: data.y + 1, z: data.z });
                      return;
                  }
                  if (relY < -0.23) {
                       setHoverCoord({ x: data.x, y: data.y - 1, z: data.z });
                       return;
                  }

                  // 2. Horizontal Neighbors (Side Faces)
                  // Angle in X/Z plane.
                  const size = 0.6;
                  let bestNeigh = null;
                  let minD = Infinity;

                  HEX_NEIGHBORS.forEach(n => {
                       const pos = hexToPixel(data.x + n.q, data.z + n.r, size);
                       // We compare world positions
                       const wx = pos.x; 
                       const wz = pos.z; 

                       const dx = wx - hitPoint!.x;
                       const dz = wz - hitPoint!.z;
                       const d = dx*dx + dz*dz;
                       if (d < minD) {
                           minD = d;
                           bestNeigh = n;
                       }
                  });

                  if (bestNeigh) {
                      setHoverCoord({ x: data.x + bestNeigh.q, y: data.y, z: data.z + bestNeigh.r });
                  }

              } else {
                  // Hit Floor 
                  // Map X/Z to Hex Grid
                  const size = 0.6;
                  const q = (2./3 * hitPoint.x) / size;
                  const r = (-1./3 * hitPoint.x + Math.sqrt(3)/3 * hitPoint.z) / size;

                  // Round to nearest Hex
                  let rx = Math.round(q);
                  let rz = Math.round(r);
                  let ry = Math.round(-q-r);

                  const x_diff = Math.abs(rx - q);
                  const y_diff = Math.abs(ry - (-q-r));
                  const z_diff = Math.abs(rz - r);

                  if (x_diff > y_diff && x_diff > z_diff) {
                      rx = -ry-rz;
                  } else if (y_diff > z_diff) {
                      // ry = -rx-rz; 
                  } else {
                      rz = -rx-ry;
                  }

                  setHoverCoord({ x: rx, y: 0, z: rz });
              }

          } else {
              // --- CUBE/TETRA LOGIC ---
              if (hitObject?.name.startsWith('voxel')) {
                 const nx = hitNormal!.x;
                 const ny = hitNormal!.y;
                 const nz = hitNormal!.z;
                 const p = hitObject.position;
                 setHoverCoord({
                     x: Math.round(p.x + nx),
                     y: Math.round(p.y + ny),
                     z: Math.round(p.z + nz)
                 });
              } else {
                 // Hit floor
                 setHoverCoord({
                     x: Math.round(hitPoint.x),
                     y: 0,
                     z: Math.round(hitPoint.z)
                 });
              }
          }
      } else {
          setHoverCoord(null);
      }
  };

  const handleClick = (e: any) => {
      e.stopPropagation();
      // If Right click on existing voxel
      if (e.button === 2) {
         raycaster.setFromCamera(pointer, camera);
         const intersects = raycaster.intersectObjects(scene.children, true);
         for(const hit of intersects) {
             if (hit.object.name.startsWith('voxel')) {
                 const userData = hit.object.userData as GridCoord;
                 onCellClick(userData.x, userData.y, userData.z, true);
                 return;
             }
         }
      }

      if (hoverCoord) {
          onCellClick(hoverCoord.x, hoverCoord.y, hoverCoord.z, false);
      }
  };

  return (
    <group 
        onPointerMove={handlePointerMove} 
        onClick={handleClick}
        onContextMenu={handleClick}
    >
      <ambientLight intensity={0.8} />
      <directionalLight position={[5, 10, 5]} intensity={1.5} />

      {cells.map(c => {
          if (currentType === ShapeType.HEX) {
              const {x, z} = hexToPixel(c.x, c.z, 0.6);
              // Vertical Spacing for Cylinders (Height 0.5)
              const hexHeight = 0.5;
              const yPos = c.y * hexHeight + (hexHeight/2);

              return (
                  <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[x, yPos, z]}
                    geometry={hexGeo}
                    material={materialHex}
                    name="voxel_hex"
                    userData={c}
                    rotation={[0, Math.PI/6, 0]} // Pointy top orientation
                  />
              );
          } else {
              return (
                <mesh 
                    key={`${c.x},${c.y},${c.z}`}
                    position={[c.x, c.y, c.z]} 
                    geometry={boxGeo} 
                    material={material}
                    name="voxel_cube"
                    userData={c}
                />
              );
          }
      })}

      {hoverCoord && (
         <group>
             {currentType === ShapeType.HEX ? (
                 <mesh 
                    position={[
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).x, 
                        hoverCoord.y * 0.5 + 0.25, 
                        hexToPixel(hoverCoord.x, hoverCoord.z, 0.6).z
                    ]} 
                    geometry={hexGeo} 
                    material={hoverMaterial}
                    rotation={[0, Math.PI/6, 0]}
                 />
             ) : (
                 <mesh position={[hoverCoord.x, hoverCoord.y, hoverCoord.z]} geometry={boxGeo} material={hoverMaterial} />
             )}
         </group>
      )}

      {/* Base Plane for Raycasting (Lowered to allow negative layer interaction) */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.5, 0]} name="base_plane" visible={false}>
          <planeGeometry args={[40, 40]} />
      </mesh>

      {/* Grid Helper Lowered to -2.5 to visualize 'underground' capacity */}
      {currentType === ShapeType.HEX ? (
           <gridHelper args={[20, 20, 0x444444, 0x111111]} position={[0, -2.5, 0]} />
      ) : (
           <gridHelper args={[20, 20, 0x444444, 0x222222]} position={[0, -2.5, 0]} />
      )}

    </group>
  );
};

// Hexagonal Architecture: Domain Layer (Inner Core)
// Zero dependencies on UI or Rendering libraries.

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Node {
  id: string;
  pos: Vec3;
  oldPos: Vec3; // For Verlet integration
  mass: number;
  friction: number;
  isFixed?: boolean;
  isHead?: boolean; // NEW: The only node that can eat

  // EDITOR METADATA (Preserves shape upon reloading)
  originalGridCoord?: { x: number; y: number; z: number }; 

  // Neural State
  activation?: number; // 0.0 to 1.0 (Visualization Glow)
  // Physics State
}

export interface Muscle {
  id: string;
  nodeA: string; // ID reference
  nodeB: string; // ID reference
  baseLength: number;
  stiffness: number;
  dnaIndex: number; // Maps to a Gene (Index in genome arrays)

  // Runtime Physics State
  currentLength?: number; 
  targetLength?: number; 

  // --- OSCILLATOR STATE (The Anti-Vibration Core) ---
  // The brain controls these parameters, not the length directly.
  phase: number;      // Current position in the sine wave (0 to 2PI)
  freq: number;       // How fast it pulses (Hz). Clamped to prevent jitter.
  amp: number;        // How much it expands (0.0 to 0.4). 
}

// Replaced simple Sine Gene with Neural Genome
export interface NeuralGenome {
  // GNN Weights: How much signal flows through each muscle (Synapse)
  synapseWeights: number[]; 
  // LSM Weights: The chaotic reservoir weights (simplified as a float array)
  reservoirWeights: number[];
  // Output Weights: Mapping the reservoir state to muscle contraction
  outputWeights: number[]; 
  // Biases for neurons
  biases: number[];
}

export interface FoodItem {
    id: string;
    pos: Vec3;
    energyValue: number;
    consumed: boolean;
}

export enum ShapeType {
  CUBE = 'CUBE', // Cartesian Lattice
  TETRAHEDRON = 'TETRAHEDRON', // Offset Lattice
  WORM = 'WORM', // Legacy
  HEX = 'HEX', // 3D Hexagonal Prism Layout
}

export interface Organism {
  id: string;
  shape: ShapeType; // NEW: Tracks the lattice type for the Architect
  nodes: Node[];
  muscles: Muscle[];
  // The Blueprint
  neuralGenome: NeuralGenome;
  // The Runtime Brain (Controller instance, not serialized usually, but here for simplicity)
  brain?: any; 

  // Stats
  fitness: number; // Distance traveled
  generation: number;

  // NEW: Metabolism & Survival
  energy: number;          // 0 to 100
  maxEnergy: number;       
  hungerTime: number;      // Time since last meal (drives exponential decay)
  isAlive: boolean;
  foodEaten: number;
  visibleFood: FoodItem[]; // Each creature has its own reality/food track
}

export interface SimulationConfig {
  gravity: number;
  friction: number;
  groundDamping: number;
  timeStep: number;
  // NEW: Structural Integrity
  shapeMemoryStrength: number;

  // NEW: Real-time Physics Tweaks
  globalStiffness: number;     // Multiplier for bone rigidity (0.1 to 2.0)
  globalContractility: number; // Multiplier for muscle power (0.0 to 2.0)
}

// --- ARCHITECT TYPES ---
export type GridCoord = { x: number; y: number; z: number };

export interface Blueprint {
    cells: Map<string, boolean>; // Key "x,y,z"
    type: ShapeType;
}

import { Organism, Node } from '../types';
import { NeuralNode } from './NeuralNode';
import { CentralPatternGenerator } from './CentralPatternGenerator';
import { VectorOps } from '../math';

export class BrainController {
  private neuralNodes: Map<string, NeuralNode> = new Map();
  private cpg: CentralPatternGenerator;
  private organism: Organism;
  private isInitialized = false;

  // Simulation Time Tracker
  private internalTime = 0;

  // Spinal Wave Props
  private headNodeId: string | null = null;
  private muscleRestDistances: Map<string, number> = new Map();

  // Decision Timer
  private decisionTimer = 0;
  private readonly DECISION_INTERVAL = 0.08; 

  // --- LEARNING MEMORY ---
  private previousEnergy: number = 0;
  private readonly VISION_RADIUS = 4.0;
  private readonly HEBBIAN_RATE = 0.15; // Learning Rate

  constructor(organism: Organism) {
    this.organism = organism;
    this.cpg = new CentralPatternGenerator(20);
    this.previousEnergy = organism.energy;

    organism.nodes.forEach(node => {
      this.neuralNodes.set(node.id, new NeuralNode(node));
    });

    if (organism.neuralGenome) {
        this.cpg.initialize(organism.neuralGenome.reservoirWeights);
    }
  }

  private initializeNervousSystem() {
      if (this.organism.nodes.length === 0) return;

      // Identify Head (The one tagged isHead, or fallback to highest Z)
      let headNode = this.organism.nodes.find(n => n.isHead);
      if (!headNode) {
          headNode = this.organism.nodes[0];
          for(const n of this.organism.nodes) {
              if (n.pos.z > headNode.pos.z) headNode = n;
          }
          // @ts-ignore
          headNode.isHead = true; 
      }
      this.headNodeId = headNode.id;

      this.organism.muscles.forEach(m => {
          const nA = this.organism.nodes.find(n => n.id === m.nodeA);
          const nB = this.organism.nodes.find(n => n.id === m.nodeB);
          if (nA && nB) {
              const midX = (nA.pos.x + nB.pos.x) / 2;
              const midY = (nA.pos.y + nB.pos.y) / 2;
              const midZ = (nA.pos.z + nB.pos.z) / 2;

              const dist = VectorOps.distance(
                  headNode!.pos, 
                  { x: midX, y: midY, z: midZ }
              );
              this.muscleRestDistances.set(m.id, dist);
          }
      });

      this.organism.muscles.forEach(m => {
          m.targetLength = m.baseLength;
          m.phase = Math.random() * Math.PI * 2; 
          m.freq = 1.0; 
          m.amp = 0.0;
      });

      this.isInitialized = true;
  }

  public update(dt: number, powerScale: number = 1.0): void {
    const genome = this.organism.neuralGenome;
    if (!genome) return;

    if (!this.isInitialized) {
        this.initializeNervousSystem();
    }

    this.internalTime += dt;

    this.decisionTimer += dt;
    if (this.decisionTimer >= this.DECISION_INTERVAL) {
        this.think(dt);
        // SELF-REWARD MECHANISM: Learn from eating
        this.learn();
        this.decisionTimer = 0;
    }

    // --- SPINAL WAVE (Motor Control) ---
    const WAVE_FREQ = 1.5; 
    const WAVE_SPEED = 1.0; 
    const FORCED_AMP = 0.15; 
    const MAX_DEFORMATION = 0.3; // Hard Clamp: Muscles can only expand/contract 30%

    this.organism.muscles.forEach(m => {
        m.phase += m.freq * dt * (Math.PI * 2);
        if (m.phase > Math.PI * 2) m.phase -= Math.PI * 2;
        const brainSignal = Math.sin(m.phase) * m.amp;

        const dist = this.muscleRestDistances.get(m.id) || 0;
        const nerveLag = dist * WAVE_SPEED;
        const spinalSignal = Math.sin(this.internalTime * WAVE_FREQ * Math.PI * 2 - nerveLag) * FORCED_AMP;

        let totalSignal = (spinalSignal + brainSignal) * powerScale;

        // SIGNAL CLAMPING: Prevent extreme distortion command
        if (totalSignal > MAX_DEFORMATION) totalSignal = MAX_DEFORMATION;
        if (totalSignal < -MAX_DEFORMATION) totalSignal = -MAX_DEFORMATION;

        const desiredLength = m.baseLength * (1 + totalSignal);

        // MUSCLE INERTIA: Slow down the reaction to prevent twitching
        // Lower value = smoother, heavier feel.
        const reactionSpeed = 0.05; 

        if (!m.targetLength) m.targetLength = m.baseLength;
        m.targetLength += (desiredLength - m.targetLength) * reactionSpeed;
        m.currentLength = m.targetLength;
    });
  }

  private think(dt: number): void {
    const genome = this.organism.neuralGenome;

    // 1. GATHER PROPRIOCEPTION (Internal Body Sense)
    let globalSensoryInput = 0;
    this.neuralNodes.forEach(nn => {
        nn.sense(dt); 
        globalSensoryInput += nn.inputSum; 
    });

    // 2. VISION (External Food Sense)
    const head = this.organism.nodes.find(n => n.isHead);
    if (head) {
        // Find nearest food
        let nearestDist = Infinity;
        let targetVec = { x: 0, y: 0, z: 0 };
        let foundFood = false;

        for (const food of this.organism.visibleFood) {
            if (food.consumed) continue;

            const dx = food.pos.x - head.pos.x;
            const dy = food.pos.y - head.pos.y;
            const dz = food.pos.z - head.pos.z;
            const distSq = dx*dx + dy*dy + dz*dz;

            if (distSq < this.VISION_RADIUS * this.VISION_RADIUS) {
                if (distSq < nearestDist) {
                    nearestDist = distSq;
                    targetVec = { x: dx, y: dy, z: dz };
                    foundFood = true;
                }
            }
        }

        if (foundFood) {
            const dist = Math.sqrt(nearestDist);
            const headNeural = this.neuralNodes.get(head.id);
            if (headNeural) {
                // INJECT SCENT SIGNAL
                // Normalize vector and scale by closeness (closer = stronger signal)
                const signalStrength = Math.max(0, 1.0 - (dist / this.VISION_RADIUS));

                // Add directional inputs to the head neuron
                // We map X/Y/Z to the inputSum. 
                // X (Left/Right), Y (Up/Down), Z (Forward)
                headNeural.inputSum += (targetVec.x / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (targetVec.y / dist) * signalStrength * 3.0; 
                headNeural.inputSum += (targetVec.z / dist) * signalStrength * 3.0; 

                // PRIMING / EXCITEMENT
                // If detecting food, increase global excitement (Input to CPG)
                // This makes the creature move more vigorously when it smells something
                globalSensoryInput += signalStrength * 2.0;
            }
        }
    }

    globalSensoryInput /= (this.neuralNodes.size || 1);

    // 3. SYNAPTIC PROPAGATION (The "Thinking")
    this.organism.muscles.forEach((muscle, i) => {
        const nnA = this.neuralNodes.get(muscle.nodeA);
        const nnB = this.neuralNodes.get(muscle.nodeB);
        if (nnA && nnB) {
            const w = genome.synapseWeights[i % genome.synapseWeights.length];
            // Bidirectional flow
            nnB.inputSum += nnA.activation * w;
            nnA.inputSum += nnB.activation * w;
        }
    });

    this.neuralNodes.forEach(nn => nn.updateActivation());

    // 4. RESERVOIR COMPUTING
    this.cpg.tick(globalSensoryInput);

    // 5. MOTOR OUTPUT
    this.organism.muscles.forEach((muscle, i) => {
        const rawAmp = this.cpg.getSignal(i, genome.outputWeights); 
        const rawFreq = this.cpg.getSignal(i + 1, genome.outputWeights); 

        const targetAmp = Math.abs(rawAmp) * 0.3; 
        const minFreq = 0.5;
        const maxFreq = 3.0; 
        const targetFreq = minFreq + ((rawFreq + 1) / 2) * (maxFreq - minFreq);

        const lerpRate = 0.1; 
        muscle.amp += (targetAmp - muscle.amp) * lerpRate;
        muscle.freq += (targetFreq - muscle.freq) * lerpRate;
    });
  }

  // --- SELF-REWARDING MECHANISM (Hebbian Learning) ---
  private learn(): void {
      const currentEnergy = this.organism.energy;

      // Calculate Reward: Did we gain energy since last check?
      const energyDelta = currentEnergy - this.previousEnergy;

      // If we ate, energyDelta will be positive (e.g. +30 from food)
      // Note: Decay happens every frame, so we need to check if delta > normal frame decay.
      // However, simplified: if energy WENT UP, it's definitely food.

      if (energyDelta > 0.5) {
          // REWARD SIGNAL!
          const reward = 1.0; 
          const genome = this.organism.neuralGenome;

          // Hebbian Update Rule: Δw = rate * reward * pre * post
          // We strengthen connections that were active during this success.

          this.organism.muscles.forEach((muscle, i) => {
            const nnA = this.neuralNodes.get(muscle.nodeA);
            const nnB = this.neuralNodes.get(muscle.nodeB);

            if (nnA && nnB) {
                const wIdx = i % genome.synapseWeights.length;

                // Correlated firing?
                // If both were active, this connection helped transfer the signal.
                const coActivity = nnA.activation * nnB.activation;

                if (coActivity > 0.1) {
                    genome.synapseWeights[wIdx] += this.HEBBIAN_RATE * reward * coActivity;

                    // Clamp weights to prevent explosion
                    if (genome.synapseWeights[wIdx] > 3.0) genome.synapseWeights[wIdx] = 3.0;
                    if (genome.synapseWeights[wIdx] < -3.0) genome.synapseWeights[wIdx] = -3.0;
                }
            }
          });

          // Also reward the Output Weights (CPG -> Muscles)
          for(let i=0; i<genome.outputWeights.length; i++) {
               // A bit harder to map directly without knowing exactly which neuron fired,
               // but we can apply a general reinforcement to the reservoir weights based on activity.
               // For MVP, Synaptic Plasticity on the body muscles is the most direct "Body Learning".
          }
      }

      this.previousEnergy = currentEnergy;
  }
}

import { Node, Muscle, Organism, SimulationConfig } from './types';
import { VectorOps } from './math';
import { BrainController } from './neural/BrainController';

export class BioPhysicsEngine {
  private config: SimulationConfig;
  private readonly MAX_VELOCITY = 12.0; // Reduced terminal velocity

  // SOLVER SETTINGS
  private readonly RELAXATION_FACTOR = 0.25; 
  private readonly ITERATIONS = 6; 

  // DAMPING SETTINGS
  private readonly BASE_MUSCLE_DAMPING = 0.08; // Increased damping to reduce twitch
  private readonly ADAPTIVE_DAMPING_FACTOR = 0.12; 
  private readonly ROTATIONAL_DRAG = 0.92; 

  // AIR RESISTANCE
  private readonly DRAG_COEFFICIENT = 0.08; 

  // FRICTION THRESHOLD
  private readonly STATIC_FRICTION_THRESHOLD = 0.2; 

  // --- SOLIDITY CONSTANTS ---
  private readonly NODE_RADIUS = 0.1; 
  private readonly HARD_CONTACT_LIMIT = 0.22; 

  constructor(config: Partial<SimulationConfig> = {}) {
    this.config = {
      gravity: -60.0, 
      friction: 0.98, // Global air friction
      groundDamping: 0.5,
      timeStep: 0.016,
      shapeMemoryStrength: 0.85, 
      globalStiffness: 1.0, // Default 100% stiffness
      globalContractility: 1.0, // Default 100% muscle power
      ...config
    };
  }

  public setConfig(config: Partial<SimulationConfig>) {
      this.config = { ...this.config, ...config };
  }

  // fastMode: If true, runs lower fidelity physics for rapid evolutionary calculation
  public updateOrganism(organism: Organism, totalTime: number, fastMode: boolean = false): void {

    // 1. NEURAL UPDATE (Only if Alive)
    if (organism.isAlive) {
        if (!organism.brain) {
            organism.brain = new BrainController(organism);
        }
        if (organism.brain instanceof BrainController) {
            // PASS CONFIGURABLE MUSCLE POWER
            organism.brain.update(this.config.timeStep, this.config.globalContractility);
        }
    } else {
        // RAGDOLL MODE: If dead, muscles lose all stiffness/power
        organism.muscles.forEach(m => {
            m.stiffness = 0.05; // Very loose
            m.amp = 0; // Stop oscillating
            m.targetLength = m.baseLength;
        });
    }

    // 2. PHYSICS INTEGRATION
    // ADAPTIVE SUBSTEPS
    const subSteps = fastMode ? 4 : 12; 
    const subDt = this.config.timeStep / subSteps;
    const gravityVec = { x: 0, y: this.config.gravity * subDt * subDt, z: 0 };

    for(let s=0; s < subSteps; s++) {
        this.integrate(organism, subDt, gravityVec);
        if (!fastMode) this.applyRotationalDrag(organism); 

        // ITERATIVE SOLVER
        // In Fast Mode, we reduce iterations slightly
        const loops = fastMode ? 4 : this.ITERATIONS;

        for (let i = 0; i < loops; i++) {
            this.resolveMuscles(organism);

            // CRITICAL OPTIMIZATION:
            // Self-Collision is O(N^2). We disable it during rapid evolution.
            if (!fastMode) {
                this.resolveSelfCollisions(organism); 
            }
        }

        this.resolveFloor(organism);
    }
  }

  private applyRotationalDrag(organism: Organism): void {
      let cx = 0, cz = 0;
      let count = 0;
      for (const n of organism.nodes) {
          cx += n.pos.x;
          cz += n.pos.z;
          count++;
      }
      if (count === 0) return;
      cx /= count;
      cz /= count;

      let angularMomentum = 0;
      let momentOfInertia = 0;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const vx = n.pos.x - n.oldPos.x;
          const vz = n.pos.z - n.oldPos.z;

          const orbitalComponent = rx * vz - rz * vx;

          angularMomentum += orbitalComponent;
          momentOfInertia += rx * rx + rz * rz;
      }

      if (momentOfInertia < 0.001) return;

      const angularVel = angularMomentum / momentOfInertia;

      for (const n of organism.nodes) {
          const rx = n.pos.x - cx;
          const rz = n.pos.z - cz;

          const dampX = -angularVel * rz * this.ROTATIONAL_DRAG;
          const dampZ =  angularVel * rx * this.ROTATIONAL_DRAG;

          n.oldPos.x += dampX;
          n.oldPos.z += dampZ;
      }
  }

  private integrate(organism: Organism, dt: number, gravityVec: {x:number, y:number, z:number}): void {
    const { friction } = this.config;
    const maxStepDist = this.MAX_VELOCITY * dt;
    const maxStepSq = maxStepDist * maxStepDist;

    for (const node of organism.nodes) {
      if (node.isFixed) continue;

      let velX = node.pos.x - node.oldPos.x;
      let velY = node.pos.y - node.oldPos.y;
      let velZ = node.pos.z - node.oldPos.z;

      // 1. QUADRATIC DRAG
      const vSq = velX*velX + velY*velY + velZ*velZ;
      if (vSq > 0.000001) {
          const vLen = Math.sqrt(vSq);
          const dragFactor = 1.0 / (1.0 + this.DRAG_COEFFICIENT * vLen);

          velX *= dragFactor;
          velY *= dragFactor;
          velZ *= dragFactor;
      }

      // 2. Base Friction
      velX *= friction;
      velY *= friction;
      velZ *= friction;

      // 3. Hard Cap (Safety Terminator)
      const distSq = velX*velX + velY*velY + velZ*velZ;
      if (distSq > maxStepSq) {
          const scale = maxStepDist / Math.sqrt(distSq);
          velX *= scale;
          velY *= scale;
          velZ *= scale;
      }

      node.oldPos = VectorOps.copy(node.pos);

      node.pos.x += velX + gravityVec.x;
      node.pos.y += velY + gravityVec.y;
      node.pos.z += velZ + gravityVec.z;
    }
  }

  private resolveMuscles(organism: Organism): void {
    const GROUND_TOLERANCE = 0.02;
    const ANCHOR_MULTIPLIER = 0.1; 
    const MEMORY_STRENGTH = this.config.shapeMemoryStrength || 0.8;
    const GLOBAL_STIFFNESS = this.config.globalStiffness; 

    for (const muscle of organism.muscles) {
        const n1 = organism.nodes.find(n => n.id === muscle.nodeA);
        const n2 = organism.nodes.find(n => n.id === muscle.nodeB);

        if (!n1 || !n2) continue;

        const dx = n2.pos.x - n1.pos.x;
        const dy = n2.pos.y - n1.pos.y;
        const dz = n2.pos.z - n1.pos.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);

        if (dist < 0.0001) continue; 

        // 1. ACTIVE MUSCLE COMPONENT (The Brain's Desire)
        let activeTarget = muscle.targetLength || muscle.baseLength;
        // Safety limit to prevent implosion
        if (activeTarget < this.HARD_CONTACT_LIMIT) activeTarget = this.HARD_CONTACT_LIMIT;

        // Active stiffness is softer than structural memory
        // SCALED BY GLOBAL STIFFNESS
        let stiffness = muscle.stiffness * 0.8 * GLOBAL_STIFFNESS; 

        const activeDiff = dist - activeTarget;

        // 2. PASSIVE MEMORY COMPONENT (The Exoskeleton)
        // This force resists deviation from the Blueprint.

        // Calculate Deformation Percentage
        const deviation = Math.abs(dist - muscle.baseLength);
        const strain = deviation / muscle.baseLength;

        // NON-LINEAR RESTORING FORCE:
        const strainBoost = 1.0 + (strain * 4.0); 

        // SCALED BY GLOBAL STIFFNESS
        const currentMemoryStrength = organism.isAlive 
            ? MEMORY_STRENGTH * strainBoost * GLOBAL_STIFFNESS
            : MEMORY_STRENGTH * 0.1 * GLOBAL_STIFFNESS;

        const baseDiff = dist - muscle.baseLength;

        // --- DUAL FORCE BLENDING ---
        const activeCorrection = activeDiff * stiffness;
        const memoryCorrection = baseDiff * currentMemoryStrength;

        // Sum the corrections. 
        let totalCorrection = activeCorrection + memoryCorrection;

        // Apply Relaxation Factor (Iterative Solver Stability)
        totalCorrection *= this.RELAXATION_FACTOR;

        // --- DAMPING (Higher damping reduces twitch) ---
        const vx1 = n1.pos.x - n1.oldPos.x;
        const vy1 = n1.pos.y - n1.oldPos.y;
        const vz1 = n1.pos.z - n1.oldPos.z;
        const vx2 = n2.pos.x - n2.oldPos.x;
        const vy2 = n2.pos.y - n2.oldPos.y;
        const vz2 = n2.pos.z - n2.oldPos.z;

        const rvx = vx2 - vx1;
        const rvy = vy2 - vy1;
        const rvz = vz2 - vz1;

        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        const relVelSq = rvx*rvx + rvy*rvy + rvz*rvz;
        const relVel = Math.sqrt(relVelSq);

        const dynamicDamping = this.BASE_MUSCLE_DAMPING + (relVel * this.ADAPTIVE_DAMPING_FACTOR);

        const vRelProj = rvx * nx + rvy * ny + rvz * nz;
        totalCorrection += vRelProj * dynamicDamping;

        // --- MOMENTUM PRESERVATION ---
        let im1 = n1.isFixed ? 0 : 1 / n1.mass;
        let im2 = n2.isFixed ? 0 : 1 / n2.mass;

        if (n1.pos.y <= GROUND_TOLERANCE) im1 *= ANCHOR_MULTIPLIER;
        if (n2.pos.y <= GROUND_TOLERANCE) im2 *= ANCHOR_MULTIPLIER;

        const totalInvMass = im1 + im2;
        if (totalInvMass === 0) continue;

        const w1 = im1 / totalInvMass;
        const w2 = im2 / totalInvMass;

        const offsetX = nx * totalCorrection;
        const offsetY = ny * totalCorrection;
        const offsetZ = nz * totalCorrection;

        if (!n1.isFixed) {
            n1.pos.x += offsetX * w1;
            n1.pos.y += offsetY * w1;
            n1.pos.z += offsetZ * w1;
        }

        if (!n2.isFixed) {
            n2.pos.x -= offsetX * w2;
            n2.pos.y -= offsetY * w2;
            n2.pos.z -= offsetZ * w2;
        }
    }
  }

  private resolveSelfCollisions(organism: Organism): void {
      const nodes = organism.nodes;
      const count = nodes.length;

      const minDistance = this.HARD_CONTACT_LIMIT; 
      const minDistanceSq = minDistance * minDistance;

      for (let i = 0; i < count; i++) {
          for (let j = i + 1; j < count; j++) {
              const n1 = nodes[i];
              const n2 = nodes[j];

              const dx = n1.pos.x - n2.pos.x;
              const dy = n1.pos.y - n2.pos.y;
              const dz = n1.pos.z - n2.pos.z;
              const distSq = dx*dx + dy*dy + dz*dz;

              if (distSq < minDistanceSq && distSq > 0.000001) {
                  const dist = Math.sqrt(distSq);
                  const overlap = minDistance - dist;

                  // Soft repulsion (Relaxed)
                  const fx = (dx / dist) * overlap * 0.2; // Gentle push
                  const fy = (dy / dist) * overlap * 0.2;
                  const fz = (dz / dist) * overlap * 0.2;

                  if (!n1.isFixed) { 
                      n1.pos.x += fx; 
                      n1.pos.y += fy; 
                      n1.pos.z += fz; 
                  }
                  if (!n2.isFixed) { 
                      n2.pos.x -= fx; 
                      n2.pos.y -= fy; 
                      n2.pos.z -= fz; 
                  }
              }
          }
      }
  }

  private resolveFloor(organism: Organism): void {
    const RADIUS = this.NODE_RADIUS;

    for (const node of organism.nodes) {
      if (node.pos.y < RADIUS) {

        node.pos.y = RADIUS;

        const vx = node.pos.x - node.oldPos.x;
        const vz = node.pos.z - node.oldPos.z;
        const velocitySq = vx*vx + vz*vz;

        // If dead, friction increases (they slump)
        const deadFrictionBonus = organism.isAlive ? 0 : 0.3;
        const gripFactor = Math.max(0, 1.0 - (node.friction || 0.5) - deadFrictionBonus);

        if (velocitySq < 0.0005) {
             node.oldPos.x = node.pos.x;
             node.oldPos.z = node.pos.z;
        } else {
             node.oldPos.x = node.pos.x - vx * gripFactor;
             node.oldPos.z = node.pos.z - vz * gripFactor;
        }
      } 
    }
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FEEDING MECHANICS
  private readonly MAGNET_RADIUS = 1.5; // Reduced: Requires head to be close
  private readonly MAGNET_FORCE = 0.4;  // Strong pull only when very close
  private readonly EAT_RADIUS = 0.4;    // Precision eating

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;
  private onNewGenerationCallback: ((pop: Organism[]) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- PHYSICS CONFIGURATION ---
  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      // Deep clone to ensure we sever references to the old simulation loop.
      // We use a replacer to safely handle any potential circular refs (like brain -> organism)
      // even though inputs *should* be clean, safety first.
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); // false = don't reset generation to 1
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          // First one is a pure clone (Elite), others are mutated
          if (i > 0) {
              this.mutateGenome(child.neuralGenome);
          }

          // Spawn Food Track for this creature
          child.visibleFood = this.generateFoodTrack(child);

          this.population.push(child);
      }

      if (this.onNewGenerationCallback) {
          this.onNewGenerationCallback(this.population);
      }
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = 40; // Abundant food to stimulate "Tree" environment

      // Level Design: "The Canopy"
      // Instead of a path, create a cloud of food around the creature's HEAD.
      // Encourages: Balancing, Reaching, Standing Up, Neck Control.

      let centerX = 0;
      let centerZ = 0;

      // Find the head to center the food cloud
      const head = organism.nodes.find(n => n.isHead);
      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      for(let i=0; i<numFood; i++) {
          // Random spherical/cylindrical distribution around HEAD
          const theta = Math.random() * Math.PI * 2;

          // Distance: Close enough to reach if leaning (0.8), far enough to need steps (3.0)
          const radius = 0.8 + Math.random() * 2.2; 

          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;

          // Verticality: 
          // 1.0 = Low Hanging Fruit (Chin level)
          // 3.5 = High Fruit (Must stand/jump)
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      // Sort by fitness temporarily to find best
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      // Return a clean clone without the BrainController instance
      // FIX: Use replacer to break circular dependency (brain -> organism -> brain)
      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);

      // Ensure current generation is saved in the organism so we can resume
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    // AUTO-CYCLE: If everyone is dead, start next generation automatically
    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 

      // FIX: Reduce Batch Duration significantly to yield to UI thread
      // 12ms allows ample time for 60fps frame budget (16ms)
      const BATCH_DURATION = 0.012; 

      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;

          // INNER LOOP: Run physics until batch time budget is exceeded
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; // Actual wall clock time estimate

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);

          // Yield to event loop immediately to handle clicks/render
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          if (!org.isAlive) return;

          // 1. HUNGER CALCULATIONS
          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
              this.calculateFitness(org); 
          }

          // 2. EATING LOGIC (With Magnetism)
          const head = org.nodes.find(n => n.isHead);
          if (!head) return; 

          // Check visible food
          let checkCount = 0;
          for (const food of org.visibleFood) {
              if (food.consumed) continue;
              if (checkCount++ > 10) break; // Check nearest 10 (optimization)

              const dist = VectorOps.distance(head.pos, food.pos);

              // MAGNET EFFECT: Pull food in if close
              if (dist < this.MAGNET_RADIUS) {
                  // Interpolate food position towards head
                  const pull = VectorOps.sub(head.pos, food.pos);
                  // Apply lerp
                  food.pos.x += pull.x * this.MAGNET_FORCE;
                  food.pos.y += pull.y * this.MAGNET_FORCE;
                  food.pos.z += pull.z * this.MAGNET_FORCE;

                  // EAT
                  if (dist < this.EAT_RADIUS) {
                      food.consumed = true;
                      org.energy += food.energyValue;
                      if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                      org.hungerTime = 0;
                      org.foodEaten++;
                  }
              }
          }
      });
  }

  private calculateFitness(org: Organism) {
      // GOAL: Eat Food + Maintain Height
      // Distance (Z) is NO LONGER relevant.

      let headY = 0;
      const head = org.nodes.find(n => n.isHead);
      if (head) headY = head.pos.y;

      // Heavy weight on eating
      // Secondary weight on standing tall (helps them reach next fruit)
      org.fitness = (org.foodEaten * 100.0) + (Math.max(0, headY) * 10.0);
  }

  private finalizeFitness() {
      this.population.forEach(org => this.calculateFitness(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    // Notification: Generation Complete (Stats)
    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);
      this.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    // Notification: New Population Ready
    if (this.onNewGenerationCallback) {
        this.onNewGenerationCallback(this.population);
    }
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      // Robust clone that ignores circular references
      const safeJson = JSON.stringify(template, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const clone: Organism = JSON.parse(safeJson);

      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; 

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                arr[i] += (Math.random() - 0.5) * 0.5;
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };
    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.onNewGenerationCallback = cb; }
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { EvolutionService } from './EvolutionService';
import { ShapeType, Organism } from '../domain/types';

export function useEvolutionLoop() {
  const serviceRef = useRef<EvolutionService>(new EvolutionService());
  const requestRef = useRef<number>(0);

  // Ref for synchronous access inside tight loops
  const isAutoEvolvingRef = useRef(false);

  const [population, setPopulation] = useState<Organism[]>([]);
  const [generation, setGeneration] = useState(1);
  const [bestFitness, setBestFitness] = useState(0);
  const [currentShape, setCurrentShape] = useState<ShapeType>(ShapeType.TETRAHEDRON);
  const [isRunning, setIsRunning] = useState(false);
  const [isAutoEvolving, setIsAutoEvolvingState] = useState(false);

  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  // New Physics State
  const [globalStiffness, setGlobalStiffnessState] = useState(1.0);
  const [globalContractility, setGlobalContractilityState] = useState(1.0);

  // Initialize
  useEffect(() => {
    const service = serviceRef.current;

    // Wire up listeners
    service.onUpdate((pop) => {
        // We do NOT set state here every frame to avoid React render thrashing.
    });

    service.onGenComplete((best, gen) => {
        setBestFitness(best.fitness);
        setGeneration(gen);
    });

    // NEW: Sync population when EvolutionService triggers an evolution internally
    service.onNewGeneration((newPop) => {
        setPopulation([...newPop]);
    });

    service.initializePopulation(currentShape);
    setPopulation([...service.population]); // Initial sync

    return () => cancelAnimationFrame(requestRef.current!);
  }, []);

  const reset = useCallback((shape: ShapeType) => {
    setIsRunning(false);

    // Stop Auto
    isAutoEvolvingRef.current = false;
    setIsAutoEvolvingState(false);

    setIsProcessing(false);
    setCurrentShape(shape);
    serviceRef.current.initializePopulation(shape);
    setPopulation([...serviceRef.current.population]);
    setGeneration(1);
    setBestFitness(0);
  }, []);

  const spawnCustom = useCallback((organism: Organism) => {
      setIsRunning(false);
      isAutoEvolvingRef.current = false;
      setIsAutoEvolvingState(false);
      setIsProcessing(false);

      serviceRef.current.setTemplateAndReset(organism);
      setPopulation([...serviceRef.current.population]);
      setGeneration(1);
      setBestFitness(0);
      setCurrentShape(ShapeType.WORM); 
  }, []);

  const evolve = useCallback(() => {
    serviceRef.current.evolve();
    setPopulation([...serviceRef.current.population]); // Update React view
    setGeneration(serviceRef.current.currentGeneration);
  }, []);

  // --- PHYSICS CONTROL HANDLERS ---
  const setGlobalStiffness = useCallback((val: number) => {
      setGlobalStiffnessState(val);
      serviceRef.current.setGlobalStiffness(val);
  }, []);

  const setGlobalContractility = useCallback((val: number) => {
      setGlobalContractilityState(val);
      serviceRef.current.setGlobalContractility(val);
  }, []);


  // --- DATA IO ---

  const saveCreature = useCallback(() => {
    const best = serviceRef.current.getBestOrganism();
    if (!best) return;

    const json = JSON.stringify(best, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `creature_gen${best.generation}_${Date.now()}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const loadCreature = useCallback((file: File, onLoaded?: (org: Organism) => void) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          try {
              const json = e.target?.result as string;
              const organism = JSON.parse(json) as Organism;

              if (!organism.nodes || !organism.muscles || !organism.neuralGenome) {
                  alert("Invalid Creature File");
                  return;
              }

              // Stop everything
              setIsRunning(false);
              isAutoEvolvingRef.current = false;
              setIsAutoEvolvingState(false);
              setIsProcessing(false);

              // Inject
              const startGen = organism.generation || 1;
              serviceRef.current.setTemplateAndReset(organism, startGen);

              setPopulation([...serviceRef.current.population]);
              setGeneration(startGen);
              setBestFitness(0);

              // Notify App
              if (onLoaded) onLoaded(organism);

          } catch (err) {
              console.error(err);
              alert("Failed to load creature file.");
          }
      };
      reader.readAsText(file);
  }, []);


  // --- AUTO EVOLUTION ---

  const runAutoEvolution = useCallback(async () => {
      if (isProcessing) return; // Prevent double entry

      setIsProcessing(true);

      try {
          // 1. Compute Generation Async (Yielding to UI)
          // We pass a callback that checks our Ref. If ref is false, service throws error.
          await serviceRef.current.computeGenerationAsync(
              10.0, 
              () => !isAutoEvolvingRef.current, // Stop Signal
              (pct) => setProgress(pct)
          );

          // 2. Evolve (Only if we finished successfully)
          evolve();

          // 3. Reset for next round
          setProgress(0);
          setIsProcessing(false);

      } catch (e) {
          // If we aborted (or other error), we catch it here.
          console.log("Evolution Stopped or Aborted");
          setIsProcessing(false);
          // Do NOT evolve. We stay on the current generation.
      }
  }, [isProcessing, evolve]);

  const toggleAutoEvolve = useCallback(() => {
      const newState = !isAutoEvolvingRef.current;
      isAutoEvolvingRef.current = newState;
      setIsAutoEvolvingState(newState);

      // If turning ON, ensure regular run is off (optional, but cleaner)
      if (newState) setIsRunning(false);
  }, []);

  const loop = useCallback(() => {
    // If neither running nor auto, stop loop
    if (!isRunning && !isAutoEvolving) return;

    if (isAutoEvolving) {
        if (!isProcessing) {
            runAutoEvolution();
        }
        // While processing, we do nothing in this loop (we wait for async in runAutoEvolution)
    } else {
        // NORMAL MODE: 60 FPS Physics
        if (isRunning) {
            serviceRef.current.step(0.016);
        }
    }

    requestRef.current = requestAnimationFrame(loop);
  }, [isRunning, isAutoEvolving, isProcessing, runAutoEvolution]);

  useEffect(() => {
    if (isRunning || isAutoEvolving) {
      requestRef.current = requestAnimationFrame(loop);
    } else {
      cancelAnimationFrame(requestRef.current!);
    }
    return () => cancelAnimationFrame(requestRef.current!);
  }, [isRunning, isAutoEvolving, loop]);

  return {
    population,
    generation,
    bestFitness,
    isRunning,
    isAutoEvolving,
    isProcessing, 
    progress,    
    currentShape,
    // Physics State
    globalStiffness,
    globalContractility,
    setGlobalStiffness,
    setGlobalContractility,
    // Actions
    setIsRunning,
    toggleAutoEvolve, 
    reset,
    evolve,
    spawnCustom,
    saveCreature,
    loadCreature
  };
}

import React, { useRef } from 'react';
import { ShapeType } from '../domain/types';

