import { Organism, ShapeType, Node, Muscle, NeuralGenome } from './types';
import { VectorOps } from './math';

export class ShapeFactory {

  static create(type: ShapeType, id: string): Organism {
    let nodes: Node[] = [];
    let muscles: Muscle[] = [];

    switch (type) {
      case ShapeType.CUBE:
        ({ nodes, muscles } = this.createCube());
        break;
      case ShapeType.WORM:
        ({ nodes, muscles } = this.createWorm(4));
        break;
      case ShapeType.TETRAHEDRON:
      default:
        ({ nodes, muscles } = this.createTetrahedron());
        break;
    }

    // Initialize Neural Genome
    const numMuscles = muscles.length;
    const reservoirSize = 20;

    const genome: NeuralGenome = {
        synapseWeights: this.randomArray(numMuscles * 2),
        reservoirWeights: this.randomArray(reservoirSize * reservoirSize),
        outputWeights: this.randomArray(numMuscles * reservoirSize),
        predictionWeights: this.randomArray(reservoirSize), // NEW: Prediction Layer
        biases: this.randomArray(nodes.length)
    };

    muscles.forEach((m, i) => m.dnaIndex = i);

    // Identify Head (Updated Heuristic: Furthest Forward, then Highest Up)
    let maxZ = -Infinity;
    nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });

    let candidates: Node[] = [];
    nodes.forEach(n => {
        if (Math.abs(n.pos.z - maxZ) < 0.1) candidates.push(n);
    });

    let headNode: Node | null = null;
    let maxY = -Infinity;
    candidates.forEach(n => {
        if (n.pos.y > maxY) {
            maxY = n.pos.y;
            headNode = n;
        }
    });

    if (headNode) {
        // @ts-ignore
        headNode.isHead = true;
    }

    return {
      id,
      shape: type, // Store shape type for editor consistency
      nodes,
      muscles,
      neuralGenome: genome,
      fitness: 0,
      generation: 1,
      // Metabolism Defaults
      energy: 100,
      maxEnergy: 100,
      hungerTime: 0,
      isAlive: true,
      foodEaten: 0,
      visibleFood: [],
      // Posture Defaults
      originalHeadY: headNode ? headNode.pos.y : 1.0,
      bestHeightScore: 0
    };
  }

  private static randomArray(size: number): number[] {
      return Array.from({ length: size }, () => (Math.random() * 1.0) - 0.5); 
  }

  private static createTetrahedron() {
    const f = 0.95; // High friction for grip
    const m = 4.0;  // Heavy mass

    const nodes: Node[] = [
      { id: 'n1', pos: { x: 0, y: 0, z: 1 }, oldPos: { x: 0, y: 0, z: 1 }, mass: m, friction: f },
      { id: 'n2', pos: { x: 1, y: 0, z: -0.7 }, oldPos: { x: 1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n3', pos: { x: -1, y: 0, z: -0.7 }, oldPos: { x: -1, y: 0, z: -0.7 }, mass: m, friction: f },
      { id: 'n4', pos: { x: 0, y: 1.5, z: 0 }, oldPos: { x: 0, y: 1.5, z: 0 }, mass: m, friction: f },
    ];
    const muscles = this.connectAll(nodes);
    return { nodes, muscles };
  }

  private static createCube() {
    const nodes: Node[] = [];
    const size = 1.0;
    const startY = 0.5;
    const f = 0.95; 
    const m = 4.0; 

    for(let x=0; x<=1; x++) {
      for(let y=0; y<=1; y++) {
        for(let z=0; z<=1; z++) {
          const px = (x - 0.5) * size;
          const py = startY + y * size;
          const pz = (z - 0.5) * size;
          nodes.push({
            id: `n${x}${y}${z}`,
            pos: { x: px, y: py, z: pz },
            oldPos: { x: px, y: py, z: pz },
            mass: m, 
            friction: f
          });
        }
      }
    }
    const muscles = this.connectDistanceThreshold(nodes, size * 1.8);
    return { nodes, muscles };
  }

  private static createWorm(segments: number) {
    const nodes: Node[] = [];
    const size = 1.0;
    const bellyFriction = 0.5; // Belly slides a bit
    const footFriction = 0.98; // Feet grip hard
    const m = 4.0; 

    for (let i = 0; i < segments; i++) {
        const offset = i * size;
        nodes.push(
            { id: `n${i}_a`, pos: { x: -0.5, y: 0, z: offset }, oldPos: { x: -0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_b`, pos: { x: 0.5, y: 0, z: offset }, oldPos: { x: 0.5, y: 0, z: offset }, mass: m, friction: footFriction },
            { id: `n${i}_top`, pos: { x: 0, y: 1, z: offset + 0.5 }, oldPos: { x: 0, y: 1, z: offset + 0.5 }, mass: m, friction: bellyFriction }
        );
    }
    return { nodes, muscles: this.connectDistanceThreshold(nodes, size * 1.5) };
  }

  private static connectAll(nodes: Node[]): Muscle[] {
    const muscles: Muscle[] = [];
    let mCount = 0;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
        muscles.push({
          id: `m${mCount++}`,
          nodeA: nodes[i].id,
          nodeB: nodes[j].id,
          baseLength: dist,
          stiffness: 1.0, // Maximum stiffness for bones
          dnaIndex: 0,
          // Init Oscillator
          phase: Math.random() * Math.PI * 2,
          freq: 1.0,
          amp: 0.0
        });
      }
    }
    return muscles;
  }

    private static connectDistanceThreshold(nodes: Node[], threshold: number): Muscle[] {
      const muscles: Muscle[] = [];
      let mCount = 0;
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const dist = VectorOps.distance(nodes[i].pos, nodes[j].pos);
          if (dist <= threshold) {
            muscles.push({
              id: `m${mCount++}`,
              nodeA: nodes[i].id,
              nodeB: nodes[j].id,
              baseLength: dist,
              stiffness: 1.0,
              dnaIndex: 0,
              // Init Oscillator
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
            });
          }
        }
      }
      return muscles;
    }
}

import { ShapeType, Organism, Node, Muscle, NeuralGenome, GridCoord } from './types';
import { VectorOps } from './math';

export class BlueprintService {
  private cells: Map<string, boolean> = new Map();
  private type: ShapeType = ShapeType.CUBE;
  private readonly GRID_SIZE = 10; // -5 to 5 bounds

  constructor() {
    this.clear();
  }

  public setType(t: ShapeType) {
    this.type = t;
  }

  public clear() {
    this.cells.clear();
  }

  public getCells(): GridCoord[] {
    const res: GridCoord[] = [];
    this.cells.forEach((val, key) => {
        if (val) {
            const [x, y, z] = key.split(',').map(Number);
            res.push({ x, y, z });
        }
    });
    return res;
  }

  public setCell(x: number, y: number, z: number, active: boolean) {
    const key = `${Math.round(x)},${Math.round(y)},${Math.round(z)}`;
    if (active) {
        this.cells.set(key, true);
    } else {
        this.cells.delete(key);
    }
  }

  public hasCell(x: number, y: number, z: number): boolean {
      return this.cells.has(`${x},${y},${z}`);
  }

  // --- HEURISTICS ---

  public generateSmallCritter() {
      this.clear();
      const rng = () => Math.random();
      const length = 4 + Math.floor(rng() * 3);
      const wideStance = rng() > 0.4;
      const legX = wideStance ? 2 : 1;

      for(let z=0; z<length; z++) this.setCell(0, 1, z, true);

      const headZ = length - 1;
      this.setCell(0, 2, headZ, true);
      if (rng() > 0.5) this.setCell(0, 3, headZ, true);

      const frontLegZ = Math.max(0, headZ - 1);
      const backLegZ = 0;

      const addLeg = (z: number) => {
          this.setCell(legX, 0, z, true);
          this.setCell(1, 1, z, true);
          if (legX === 2) this.setCell(1, 0, z, true);
      };

      addLeg(backLegZ);
      addLeg(frontLegZ);

      for(let z=1; z < length - 1; z++) {
           if (rng() > 0.6) this.setCell(1, 1, z, true);
      }
      this.applyMirrorX();
  }

  public generateLargeBeast() {
    this.clear();
    const rng = () => Math.random();
    const range = (min: number, max: number) => Math.floor(Math.random() * (max - min + 1)) + min;

    const bodyLength = range(5, 8);
    const bodyHeight = range(2, 4); 
    const zOffset = -Math.floor(bodyLength / 2);

    for (let z = 0; z < bodyLength; z++) {
        const absZ = z + zOffset;
        this.setCell(0, bodyHeight, absZ, true);
        if (rng() > 0.4) this.setCell(0, bodyHeight + 1, absZ, true);
        if (rng() > 0.4 && bodyHeight > 1) this.setCell(0, bodyHeight - 1, absZ, true);
    }

    const numLegPairs = range(2, 4); 
    const legSpacing = Math.floor(bodyLength / numLegPairs);

    for (let i = 0; i < numLegPairs; i++) {
        const zIndex = (i * legSpacing) + Math.floor(legSpacing/2);
        if (zIndex >= bodyLength) continue;

        const startZ = zIndex + zOffset;
        const startY = bodyHeight;
        const startX = 0;
        let cx = startX;
        let cy = startY;
        let cz = startZ;

        cx++;
        this.setCell(cx, cy, cz, true);

        let safety = 0;
        while (cy > 0 && safety++ < 10) {
            const moveDown = rng() > 0.3; 
            if (moveDown) cy--;
            else {
                if (rng() > 0.4) cx++; 
                else cz += (rng() > 0.5 ? 1 : -1); 
            }
            this.setCell(cx, cy, cz, true);
        }

        if (cy === 0) {
            this.setCell(cx + 1, 0, cz, true);
            this.setCell(cx - 1, 0, cz, true);
        }
    }

    const headZ = (bodyLength - 1) + zOffset + 1;
    this.setCell(0, bodyHeight + 1, headZ, true);
    this.setCell(0, bodyHeight, headZ, true);
    this.setCell(0, bodyHeight - 1, headZ, true);

    this.applyMirrorX();
  }

  public applyWorm(length: number) {
      let curr = { x: 0, y: 0, z: 0 };
      this.setCell(0, 0, 0, true);

      for(let i=0; i<length; i++) {
          const axis = Math.floor(Math.random() * 3);
          const dir = Math.random() > 0.5 ? 1 : -1;

          if (axis === 0) curr.x += dir;
          if (axis === 1) curr.y += dir;
          if (axis === 2) curr.z += dir;
          if (Math.abs(curr.x) > 4) curr.x -= dir;
          if (Math.abs(curr.y) > 4) curr.y -= dir;
          if (Math.abs(curr.z) > 4) curr.z -= dir;

          this.setCell(curr.x, curr.y, curr.z, true);
      }
  }

  public applyMirrorX() {
      const newCells = new Map<string, boolean>();
      this.cells.forEach((_, key) => {
          const [x, y, z] = key.split(',').map(Number);
          newCells.set(key, true);

          if (this.type === ShapeType.HEX) {
              const mq = -x;
              const mr = z + x; 
              newCells.set(`${mq},${y},${mr}`, true);
          } else {
             const mx = -x;
             newCells.set(`${mx},${y},${z}`, true);
          }
      });
      this.cells = newCells;
  }

  public applyFloorFill() {
      for(let x=-2; x<=2; x++) {
          for(let z=-2; z<=2; z++) {
              this.setCell(x, 0, z, true);
          }
      }
  }

  public importOrganism(org: Organism) {
      this.clear();
      this.type = org.shape || ShapeType.CUBE; 

      let hasMetadata = false;
      for (const node of org.nodes) {
          if (node.originalGridCoord) {
              hasMetadata = true;
              this.setCell(node.originalGridCoord.x, node.originalGridCoord.y, node.originalGridCoord.z, true);
          }
      }

      if (hasMetadata) return;

      const scale = 0.8;

      // Legacy Fallback: Detect Min Y to prevent floor-clipping
      let minY = Infinity;
      for (const node of org.nodes) {
          if (node.pos.y < minY) minY = node.pos.y;
      }

      // Normalize floor to 0
      const floorBias = (minY < 0.2) ? minY - 0.5 : 0; // If close to 0, assume it was based at 0.5 (y=0)

      for (const node of org.nodes) {
          const px = node.pos.x;
          // Shift down relative to estimated floor, then scale
          const py = node.pos.y;
          const pz = node.pos.z;

          let gx = 0, gy = 0, gz = 0;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6;
              const hexHeight = scale * 0.7;
              const q = px / (size * 1.5);
              const r = (pz / (size * Math.sqrt(3))) - q/2;
              const y = (py - 0.5) / hexHeight;
              gx = Math.round(q);
              gy = Math.round(y);
              gz = Math.round(r);
          } else if (this.type === ShapeType.TETRAHEDRON) {
              const y = (py - 0.5) / (scale * 0.82);
              gy = Math.round(y);
              const isOdd = gy % 2 !== 0;
              const offset = isOdd ? scale * 0.5 : 0;
              const x = (px - offset) / scale;
              const z = (pz - offset) / scale;
              gx = Math.round(x);
              gz = Math.round(z);
          } else {
              gx = Math.round(px / scale);
              // Simple conversion without complex normalization for CUBE as it's most common
              gy = Math.round((py - 0.5) / scale);
              gz = Math.round(pz / scale);
          }
          this.setCell(gx, gy, gz, true);
      }
  }

  // --- EXPORT TO PHYSICS WITH BRAIN GRAFTING ---

  public generateOrganism(id: string, source?: Organism): Organism {
      const nodes: Node[] = [];
      const muscles: Muscle[] = [];
      const coordToNodeId = new Map<string, string>();
      const createdMuscles = new Set<string>();

      const activeCoords = this.getCells();
      if (activeCoords.length === 0) {
          this.setCell(0,0,0, true);
          this.setCell(0,1,0, true);
          activeCoords.push({x:0,y:0,z:0}, {x:0,y:1,z:0});
      }

      // --- HEIGHT NORMALIZATION ---
      // Ensure the creature sits on the floor regardless of editor position
      let minY = Infinity;
      activeCoords.forEach(c => { if(c.y < minY) minY = c.y; });
      const heightOffset = -minY; // e.g. if min is -2, add 2. if min is 5, subtract 5? No, align bottom to 0.

      const scale = 0.8; 
      const mass = 1.0; 
      const friction = 0.8;

      activeCoords.forEach((c) => {
          const nodeId = `n_${c.x}_${c.y}_${c.z}`;
          coordToNodeId.set(`${c.x},${c.y},${c.z}`, nodeId);

          let px = 0, py = 0, pz = 0;

          // Apply height shift to Physics Y only
          const yLevel = c.y + heightOffset;

          if (this.type === ShapeType.HEX) {
              const size = scale * 0.6; 
              const q = c.x;
              const r = c.z;
              px = size * 1.5 * q;
              pz = size * Math.sqrt(3) * (r + q/2);
              const hexHeight = scale * 0.7; 
              py = 0.5 + yLevel * hexHeight; 
          } else if (this.type === ShapeType.TETRAHEDRON) {
              px = c.x * scale;
              pz = c.z * scale;
              if (c.y % 2 !== 0) {
                  px += scale * 0.5;
                  pz += scale * 0.5;
              }
              py = yLevel * (scale * 0.82) + 0.5;
          } else {
              px = c.x * scale;
              py = yLevel * scale + 0.5;
              pz = c.z * scale;
          }

          nodes.push({
              id: nodeId,
              pos: { x: px, y: py, z: pz },
              oldPos: { x: px, y: py, z: pz },
              mass,
              friction,
              originalGridCoord: { x: c.x, y: c.y, z: c.z }
          });
      });

      // Head Logic
      let maxZ = -Infinity;
      nodes.forEach(n => { if (n.pos.z > maxZ) maxZ = n.pos.z; });
      const candidatesZ = nodes.filter(n => Math.abs(n.pos.z - maxZ) < 0.1);
      let maxY = -Infinity;
      candidatesZ.forEach(n => { if (n.pos.y > maxY) maxY = n.pos.y; });
      const candidatesY = candidatesZ.filter(n => Math.abs(n.pos.y - maxY) < 0.1);
      let headNode: Node | null = null;
      let minAbsX = Infinity;
      candidatesY.forEach(n => {
          const absX = Math.abs(n.pos.x);
          if (absX < minAbsX) {
              minAbsX = absX;
              headNode = n;
          }
      });
      if (headNode) {
          // @ts-ignore
          headNode.isHead = true;
      }

      // Muscle Creation
      const addMuscle = (n1: string, n2: string, stiffness: number = 0.8) => {
          const k = [n1, n2].sort().join('-');
          if (createdMuscles.has(k)) return;

          const node1 = nodes.find(n => n.id === n1);
          const node2 = nodes.find(n => n.id === n2);
          if (!node1 || !node2) return;

          const dist = VectorOps.distance(node1.pos, node2.pos);
          muscles.push({
              id: `m_${k}`,
              nodeA: n1,
              nodeB: n2,
              baseLength: dist,
              stiffness: stiffness, 
              dnaIndex: muscles.length,
              phase: Math.random() * Math.PI * 2,
              freq: 1.0,
              amp: 0.0
          });
          createdMuscles.add(k);
      };

      activeCoords.forEach(c => {
          const myId = coordToNodeId.get(`${c.x},${c.y},${c.z}`);
          if (!myId) return;

          if (this.type === ShapeType.HEX) {
              const neighbors = [
                  {dq: 1, dr: 0}, {dq: 1, dr: -1}, {dq: 0, dr: -1},
                  {dq: -1, dr: 0}, {dq: -1, dr: 1}, {dq: 0, dr: 1}
              ];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dq},${c.y},${c.z+off.dr}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const vertical = [{dy:1}, {dy:-1}];
              vertical.forEach(off => {
                 const targetKey = `${c.x},${c.y+off.dy},${c.z}`;
                 const targetId = coordToNodeId.get(targetKey);
                 if (targetId) addMuscle(myId, targetId, 1.0);
              });
              neighbors.forEach(off => {
                 const targetKeyUp = `${c.x+off.dq},${c.y+1},${c.z+off.dr}`;
                 const targetIdUp = coordToNodeId.get(targetKeyUp);
                 if (targetIdUp) addMuscle(myId, targetIdUp, 0.8);
              });

          } else if (this.type === ShapeType.CUBE) {
              const neighbors = [{dx:1, dy:0, dz:0}, {dx:-1, dy:0, dz:0}, {dx:0, dy:1, dz:0}, {dx:0, dy:-1, dz:0}, {dx:0, dy:0, dz:1}, {dx:0, dy:0, dz:-1}];
              neighbors.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
              const diagonals = [{dx:1, dy:1, dz:0}, {dx:1, dy:-1, dz:0}, {dx:0, dy:1, dz:1}, {dx:0, dy:1, dz:-1}, {dx:1, dy:0, dz:1}, {dx:1, dy:0, dz:-1}];
              diagonals.forEach(off => {
                  const targetKey = `${c.x+off.dx},${c.y+off.dy},${c.z+off.dz}`;
                  const targetId = coordToNodeId.get(targetKey);
                  if (targetId) addMuscle(myId, targetId, 1.0);
              });
          } else if (this.type === ShapeType.TETRAHEDRON) {
              for(let x=-1; x<=1; x++) {
                  for(let y=-1; y<=1; y++) {
                      for(let z=-1; z<=1; z++) {
                          if (x===0 && y===0 && z===0) continue;
                          const targetKey = `${c.x+x},${c.y+y},${c.z+z}`;
                          const targetId = coordToNodeId.get(targetKey);
                          if (targetId) addMuscle(myId, targetId, 1.0);
                      }
                  }
              }
          }
      });

      // 4. Genome Init & Grafting (Unchanged logic, just keeping structure)
      const numMuscles = muscles.length;
      const reservoirSize = 20;
      const genome: NeuralGenome = {
        synapseWeights: Array.from({ length: numMuscles * 2 }, () => (Math.random() - 0.5)),
        reservoirWeights: Array.from({ length: reservoirSize * reservoirSize }, () => (Math.random() - 0.5)),
        outputWeights: Array.from({ length: numMuscles * reservoirSize }, () => (Math.random() - 0.5)),
        predictionWeights: Array.from({ length: reservoirSize }, () => (Math.random() - 0.5)),
        biases: Array.from({ length: nodes.length }, () => (Math.random() - 0.5))
      };

      if (source && source.neuralGenome) {
          const oldGenome = source.neuralGenome;
          const oldMuscles = source.muscles;
          const oldNodes = source.nodes;

          if (oldGenome.reservoirWeights.length === genome.reservoirWeights.length) {
              genome.reservoirWeights = [...oldGenome.reservoirWeights];
          }

          if (oldGenome.predictionWeights && oldGenome.predictionWeights.length === genome.predictionWeights.length) {
              genome.predictionWeights = [...oldGenome.predictionWeights];
          }

          muscles.forEach((newM, i) => {
              const match = oldMuscles.find(om => om.id === newM.id);
              if (match) {
                  const oldIdx = match.dnaIndex || 0;
                  const newIdx = i;
                  if (oldGenome.synapseWeights[oldIdx] !== undefined) {
                      genome.synapseWeights[newIdx] = oldGenome.synapseWeights[oldIdx];
                  }
                  const startOld = oldIdx * reservoirSize;
                  const startNew = newIdx * reservoirSize;
                  for(let k=0; k<reservoirSize; k++) {
                      if (oldGenome.outputWeights[startOld+k] !== undefined) {
                          genome.outputWeights[startNew+k] = oldGenome.outputWeights[startOld+k];
                      }
                  }
              }
          });

          nodes.forEach((newN, i) => {
              const match = oldNodes.find(on => on.id === newN.id);
              if (match) {
                  const oldNodeIdx = oldNodes.findIndex(on => on.id === newN.id);
                  if (oldNodeIdx !== -1 && oldGenome.biases[oldNodeIdx] !== undefined) {
                      genome.biases[i] = oldGenome.biases[oldNodeIdx];
                  }
              }
          });
      }

      return {
          id,
          shape: this.type,
          nodes,
          muscles,
          neuralGenome: genome,
          fitness: source ? source.fitness : 0,
          generation: source ? source.generation : 1,
          energy: 100,
          maxEnergy: 100,
          hungerTime: 0,
          isAlive: true,
          foodEaten: 0,
          visibleFood: [],
          // Posture Init
          originalHeadY: headNode ? headNode.pos.y : 1.0,
          bestHeightScore: 0
      };
  }
}

import { BioPhysicsEngine } from '../domain/BioPhysicsEngine';
import { Organism, ShapeType, NeuralGenome, FoodItem, Node } from '../domain/types';
import { ShapeFactory } from '../domain/ShapeFactory';
import { VectorOps } from '../domain/math';

export class EvolutionService {
  public population: Organism[] = [];
  public currentGeneration = 1;
  public simulationTime = 0;

  private engine: BioPhysicsEngine;
  private populationSize = 20;
  private mutationRate = 0.05; 
  private template: Organism | null = null; 

  // METABOLISM CONSTANTS
  private readonly START_ENERGY = 100;
  private readonly BASE_DECAY = 4.0; 
  private readonly HUNGER_ACCEL = 1.15; 
  private readonly FOOD_ENERGY = 30;

  // FITNESS WEIGHTS (Tweakable)
  public foodWeight = 100.0;
  public heightWeight = 10.0;

  // FEEDING MECHANICS
  private readonly MAGNET_RADIUS = 1.5; // Reduced: Requires head to be close
  private readonly MAGNET_FORCE = 0.4;  // Strong pull only when very close
  private readonly EAT_RADIUS = 0.4;    // Precision eating

  private onUpdateCallback: ((pop: Organism[], time: number) => void) | null = null;
  private onGenCompleteCallback: ((best: Organism, gen: number) => void) | null = null;
  private onNewGenerationCallback: ((pop: Organism[]) => void) | null = null;

  constructor() {
    this.engine = new BioPhysicsEngine();
  }

  // --- PHYSICS CONFIGURATION ---
  public setGlobalStiffness(val: number) {
      this.engine.setConfig({ globalStiffness: val });
  }

  public setGlobalContractility(val: number) {
      this.engine.setConfig({ globalContractility: val });
  }

  // --- INITIALIZATION ---

  public initializePopulation(shape: ShapeType): void {
    this.template = ShapeFactory.create(shape, 'template');
    this.spawnGenerationFromTemplate(true);
  }

  public setTemplateAndReset(organism: Organism, startGeneration: number = 1): void {
      const safeJson = JSON.stringify(organism, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      this.template = JSON.parse(safeJson);

      this.currentGeneration = startGeneration;
      this.spawnGenerationFromTemplate(false); 
  }

  private spawnGenerationFromTemplate(resetGen: boolean): void {
      if (!this.template) return;

      this.population = [];
      if (resetGen) this.currentGeneration = 1;
      this.simulationTime = 0;

      for (let i = 0; i < this.populationSize; i++) {
          const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${i}`);

          if (i > 0) {
              this.mutateGenome(child.neuralGenome);
          }

          child.visibleFood = this.generateFoodTrack(child);
          this.population.push(child);
      }

      if (this.onNewGenerationCallback) {
          this.onNewGenerationCallback(this.population);
      }
  }

  private generateFoodTrack(organism: Organism): FoodItem[] {
      const food: FoodItem[] = [];
      const numFood = 40; 

      let centerX = 0;
      let centerZ = 0;

      const head = organism.nodes.find(n => n.isHead);
      if (head) {
          centerX = head.pos.x;
          centerZ = head.pos.z;
      }

      for(let i=0; i<numFood; i++) {
          const theta = Math.random() * Math.PI * 2;
          const radius = 0.8 + Math.random() * 2.2; 
          const x = centerX + Math.cos(theta) * radius;
          const z = centerZ + Math.sin(theta) * radius;
          const y = 1.0 + Math.random() * 2.5;

          food.push({
              id: `f_${i}`,
              pos: { x, y, z },
              energyValue: this.FOOD_ENERGY,
              consumed: false
          });
      }
      return food;
  }

  // --- SERIALIZATION ---

  public getBestOrganism(): Organism | null {
      if (this.population.length === 0) return null;
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      const best = sorted[0];

      const safeJson = JSON.stringify(best, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const cleanCopy = JSON.parse(safeJson);
      cleanCopy.generation = this.currentGeneration;

      return cleanCopy;
  }

  // --- LOOP ---

  public step(dt: number): void {
    this.simulationTime += dt;
    this.updatePhysics(dt, false);
    this.updateMetabolism(dt);

    // Social Imitation
    if (Math.floor(this.simulationTime * 100) % 100 === 0) {
        this.applySocialLearning();
    }

    const allDead = !this.population.some(org => org.isAlive);
    if (allDead) {
        this.evolve();
    }

    if (this.onUpdateCallback) {
      this.onUpdateCallback(this.population, this.simulationTime);
    }
  }

  private applySocialLearning() {
      const sorted = [...this.population].sort((a, b) => b.fitness - a.fitness);
      if (sorted.length < 2) return;

      const leader = sorted[0];
      const bottomHalfStart = Math.floor(sorted.length / 2);

      for(let i=bottomHalfStart; i<sorted.length; i++) {
          const learner = sorted[i];
          if (!learner.isAlive) continue;

          const learningRate = 0.05; 
          const lg = learner.neuralGenome;
          const bg = leader.neuralGenome;

          for(let k=0; k<lg.synapseWeights.length; k++) {
              if (bg.synapseWeights[k] !== undefined) {
                  lg.synapseWeights[k] += (bg.synapseWeights[k] - lg.synapseWeights[k]) * learningRate;
              }
          }
      }
  }

  public async computeGenerationAsync(
    maxSafetyTime: number, 
    shouldStop: () => boolean, 
    onProgress?: (pct: number) => void
  ): Promise<void> {
      const dt = 0.016; 
      const BATCH_DURATION = 0.012; 
      let allDead = false;

      while (!allDead && this.simulationTime < maxSafetyTime) {
          if (shouldStop()) throw new Error("Evolution Aborted");

          let batchTime = 0;
          while (batchTime < BATCH_DURATION && !allDead && this.simulationTime < maxSafetyTime) {
              this.simulationTime += dt;
              batchTime += dt; 

              this.updatePhysics(dt, true);
              this.updateMetabolism(dt); 

              if (Math.abs(this.simulationTime % 1.0) < dt) {
                  this.applySocialLearning();
              }

              allDead = !this.population.some(org => org.isAlive);
          }

          const deadCount = this.population.filter(o => !o.isAlive).length;
          const pct = deadCount / this.populationSize;

          if (onProgress) onProgress(pct);
          await new Promise(resolve => setTimeout(resolve, 0));
      }

      this.finalizeFitness();
  }

  private updatePhysics(dt: number, fastMode: boolean): void {
    this.population.forEach(org => {
      this.engine.updateOrganism(org, this.simulationTime, fastMode);
    });
  }

  private updateMetabolism(dt: number): void {
      this.population.forEach(org => {
          if (!org.isAlive) return;

          // 1. HUNGER CALCULATIONS
          org.hungerTime += dt;
          const hungerMultiplier = Math.pow(this.HUNGER_ACCEL, org.hungerTime);
          const loss = this.BASE_DECAY * hungerMultiplier * dt;
          org.energy -= loss;

          if (org.energy <= 0) {
              org.energy = 0;
              org.isAlive = false;
          }

          // 2. EATING LOGIC
          const head = org.nodes.find(n => n.isHead);
          if (head) {
            let checkCount = 0;
            for (const food of org.visibleFood) {
                if (food.consumed) continue;
                if (checkCount++ > 10) break; 

                const dist = VectorOps.distance(head.pos, food.pos);
                if (dist < this.MAGNET_RADIUS) {
                    const pull = VectorOps.sub(head.pos, food.pos);
                    food.pos.x += pull.x * this.MAGNET_FORCE;
                    food.pos.y += pull.y * this.MAGNET_FORCE;
                    food.pos.z += pull.z * this.MAGNET_FORCE;

                    if (dist < this.EAT_RADIUS) {
                        food.consumed = true;
                        org.energy += food.energyValue;
                        if (org.energy > org.maxEnergy) org.energy = org.maxEnergy;
                        org.hungerTime = 0;
                        org.foodEaten++;
                    }
                }
            }
          }

          // 3. LIVE FITNESS UPDATE
          this.calculateFitness(org);
      });
  }

  private calculateFitness(org: Organism) {
      let headY = 0;
      const head = org.nodes.find(n => n.isHead);
      if (head) headY = head.pos.y;

      // NEW METRIC: POSTURE MATCHING
      // Reward minimizing the distance between Current Head Y and Original Head Y.
      // This incentivizes the creature to return to its "intended state".

      const targetY = org.originalHeadY || 1.0;
      const dist = Math.abs(targetY - headY);

      // Normalize: 1.0 means perfect match. 0.0 means off by more than targetY (e.g. fallen flat).
      // We clamp negative values to 0.
      const currentHeightScore = Math.max(0, 1.0 - (dist / targetY));

      // TRACK PEAK PERFORMANCE
      // We want to reward them for achieving the pose even once, 
      // rather than punishing them for falling later (at first).
      if (currentHeightScore > org.bestHeightScore) {
          org.bestHeightScore = currentHeightScore;
      }

      // WEIGHTED SCORE
      // We use bestHeightScore to reward capacity, not just current state.
      // But for display purposes, usually fitness is a growing number.
      org.fitness = (org.foodEaten * this.foodWeight) + (org.bestHeightScore * this.heightWeight);
  }

  private finalizeFitness() {
      this.population.forEach(org => this.calculateFitness(org));
  }

  public evolve(): void {
    if (!this.template) return;

    this.finalizeFitness(); 

    // 1. Selection
    this.population.sort((a, b) => b.fitness - a.fitness);
    const survivorsCount = Math.floor(this.populationSize * 0.25);
    const survivors = this.population.slice(0, survivorsCount);
    const bestOrganism = survivors[0];

    if (this.onGenCompleteCallback) {
      this.onGenCompleteCallback(bestOrganism, this.currentGeneration);
    }

    // 2. Reproduction
    this.currentGeneration++;
    const nextGen: Organism[] = [];

    // Elitism
    const champion = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_champ`);
    champion.neuralGenome = this.cloneGenome(bestOrganism.neuralGenome);
    champion.visibleFood = this.generateFoodTrack(champion);
    nextGen.push(champion);

    // Fill
    while (nextGen.length < this.populationSize) {
      const parent = survivors[Math.floor(Math.random() * survivors.length)];
      const child = this.createOrganismFromTemplate(this.template, `gen${this.currentGeneration}_${nextGen.length}`);
      child.neuralGenome = this.cloneGenome(parent.neuralGenome);
      this.mutateGenome(child.neuralGenome);
      child.visibleFood = this.generateFoodTrack(child);
      nextGen.push(child);
    }

    this.population = nextGen;
    this.simulationTime = 0;

    if (this.onNewGenerationCallback) {
        this.onNewGenerationCallback(this.population);
    }
  }

  // --- HELPERS ---

  private createOrganismFromTemplate(template: Organism, newId: string): Organism {
      const safeJson = JSON.stringify(template, (key, value) => {
          if (key === 'brain') return undefined;
          return value;
      });
      const clone: Organism = JSON.parse(safeJson);

      clone.id = newId;
      clone.fitness = 0;
      clone.brain = undefined; 

      clone.nodes.forEach(n => {
          n.oldPos = { x: n.pos.x, y: n.pos.y, z: n.pos.z };
          n.activation = 0;
      });

      clone.energy = this.START_ENERGY;
      clone.maxEnergy = this.START_ENERGY;
      clone.hungerTime = 0;
      clone.isAlive = true;
      clone.foodEaten = 0;
      clone.visibleFood = []; 

      // Reset Posture Scoring for new run
      clone.bestHeightScore = 0;

      // Preserve Original Head Y from Template (Crucial)
      clone.originalHeadY = template.originalHeadY;

      return clone;
  }

  private cloneGenome(source: NeuralGenome): NeuralGenome {
      return {
          synapseWeights: [...source.synapseWeights],
          reservoirWeights: [...source.reservoirWeights],
          outputWeights: [...source.outputWeights],
          predictionWeights: source.predictionWeights ? [...source.predictionWeights] : [], 
          biases: [...source.biases]
      };
  }

  private mutateGenome(genome: NeuralGenome): void {
    const mutateArray = (arr: number[]) => {
        if (!arr) return;
        for(let i=0; i<arr.length; i++) {
            if (Math.random() < this.mutationRate) {
                arr[i] += (Math.random() - 0.5) * 0.5;
                if (arr[i] > 2) arr[i] = 2;
                if (arr[i] < -2) arr[i] = -2;
            }
        }
    };
    mutateArray(genome.synapseWeights);
    mutateArray(genome.reservoirWeights);
    mutateArray(genome.outputWeights);
    mutateArray(genome.predictionWeights);
    mutateArray(genome.biases);
  }

  public onUpdate(cb: (pop: Organism[], time: number) => void) { this.onUpdateCallback = cb; }
  public onGenComplete(cb: (best: Organism, gen: number) => void) { this.onGenCompleteCallback = cb; }
  public onNewGeneration(cb: (pop: Organism[]) => void) { this.onNewGenerationCallback = cb; }
}

import React, { useRef } from 'react';
import { ShapeType } from '../domain/types';

interface DashboardProps {
  generation: number;
  currentStats: { fitness: number; foodEaten: number; height: number }; // Height here now conveys Posture Score (0-1) effectively
  isRunning: boolean;
  isAutoEvolving: boolean;
  onReset: (shape: ShapeType) => void;
  onToggleRun: () => void;
  onToggleAutoEvolve: () => void;
  showBestOnly: boolean;
  setShowBestOnly: (val: boolean) => void;
  currentShape: ShapeType;
  isProcessing?: boolean;
  progress?: number;

  // Physics Controls
  globalStiffness?: number;
  setGlobalStiffness?: (val: number) => void;
  globalContractility?: number;
  setGlobalContractility?: (val: number) => void;

  // Fitness Controls
  foodWeight?: number;
  setFoodWeight?: (val: number) => void;
  heightWeight?: number;
  setHeightWeight?: (val: number) => void;

  // Data IO
  onSave?: () => void;
  onLoad?: (file: File) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({
  generation,
  currentStats,
  isRunning,
  isAutoEvolving,
  onReset,
  onToggleRun,
  onToggleAutoEvolve,
